    // =========================================================================
    #region OllamaProvider

    /// <summary>
    /// LLM inference provider using a local Ollama server.
    /// Supports text generation, chat completions, embeddings, and model management
    /// via Ollama's REST API.
    /// </summary>
    public sealed class OllamaProvider : ILlmInferenceProvider
    {
        private readonly HttpClient _httpClient;
        private readonly string _baseUrl;
        private readonly int _timeoutSeconds;
        private readonly bool _ownsHttpClient;
        private volatile bool _disposed;
        private volatile LlmStatus _status = LlmStatus.Unavailable;
        private readonly ConcurrentDictionary<string, ModelInfo> _modelCache;
        private readonly List<string> _availableModelNames;
        private string _defaultModel;
        private CancellationTokenSource? _currentCts;
        private long _totalTokensGenerated;
        private long _totalRequests;

        /// <inheritdoc/>
        public string ProviderName => "Ollama";

        /// <inheritdoc/>
        public bool RequiresNetwork => false;

        /// <inheritdoc/>
        public LlmStatus Status => _status;

        /// <inheritdoc/>
        public LlmProviderMode Mode => LlmProviderMode.LocalOllama;

        /// <inheritdoc/>
        public IReadOnlyList<ModelInfo> AvailableModels =>
            _modelCache.Values.ToList().AsReadOnly();

        /// <inheritdoc/>
        public ProviderHealth Health { get; private set; } = new() { ProviderName = "Ollama" };

        /// <summary>Total tokens generated since initialization.</summary>
        public long TotalTokensGenerated => Interlocked.Read(ref _totalTokensGenerated);

        /// <summary>
        /// Initializes a new Ollama provider.
        /// </summary>
        /// <param name="baseUrl">Base URL of the Ollama server (e.g., "http://localhost:11434").</param>
        /// <param name="defaultModel">Default model to use for requests.</param>
        /// <param name="timeoutSeconds">Request timeout in seconds.</param>
        /// <param name="httpClient">Optional shared HttpClient instance.</param>
        public OllamaProvider(
            string baseUrl = "http://localhost:11434",
            string defaultModel = "llama3:8b",
            int timeoutSeconds = 120,
            HttpClient? httpClient = null)
        {
            var validated = Synapse.Core.Security.UrlSecurity.ValidateOutboundUri(
                baseUrl?.TrimEnd('/') ?? "http://localhost:11434",
                allowLoopbackHttp: true);
            _baseUrl = validated.ToString().TrimEnd('/');
            _defaultModel = defaultModel ?? "llama3:8b";
            _timeoutSeconds = timeoutSeconds;
            _modelCache = new ConcurrentDictionary<string, ModelInfo>(StringComparer.OrdinalIgnoreCase);
            _availableModelNames = new List<string>();

            if (httpClient != null)
            {
                _httpClient = httpClient;
                _ownsHttpClient = false;
            }
            else
            {
                _httpClient = Synapse.Core.Security.UrlSecurity.CreateSafeHttpClient(
                    TimeSpan.FromSeconds(timeoutSeconds + 30));
                _ownsHttpClient = true;
            }
        }

        /// <summary>
        /// Discovers available models from the Ollama server.
        /// </summary>
        /// <param name="cancellationToken">Cancellation token.</param>
        /// <returns>List of available model names.</returns>
        public async Task<IReadOnlyList<string>> DiscoverModelsAsync(
            CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();

            try
            {
                var response = await _httpClient.GetAsync($"{_baseUrl}/api/tags", cancellationToken);
                response.EnsureSuccessStatusCode();

                var json = await response.Content.ReadAsStringAsync(cancellationToken);
                using var doc = JsonDocument.Parse(json);

                _availableModelNames.Clear();
                _modelCache.Clear();

                if (doc.RootElement.TryGetProperty("models", out var models))
                {
                    foreach (var model in models.EnumerateArray())
                    {
                        var name = model.TryGetProperty("name", out var nameProp)
                            ? nameProp.GetString() ?? ""
                            : "";

                        if (string.IsNullOrEmpty(name)) continue;

                        _availableModelNames.Add(name);

                        long size = 0;
                        if (model.TryGetProperty("size", out var sizeProp))
                            size = sizeProp.GetInt64();

                        string modifiedAt = "";
                        if (model.TryGetProperty("modified_at", out var modProp))
                            modifiedAt = modProp.GetString() ?? "";

                        _modelCache[name] = new ModelInfo
                        {
                            ModelId = name,
                            DisplayName = name,
                            Provider = "Ollama",
                            ContextWindow = 4096,
                            MaxOutputTokens = 2048,
                            Tokenizer = TokenizerType.BPE,
                            VocabularySize = 32000,
                            EstimatedVramMb = (int)(size / (1024 * 1024)),
                            SupportsVision = name.Contains("vision", StringComparison.OrdinalIgnoreCase),
                            SupportsFunctionCalling = false,
                            SupportsEmbeddings = name.Contains("embed", StringComparison.OrdinalIgnoreCase),
                            InputCostPer1MTokens = 0m,
                            OutputCostPer1MTokens = 0m
                        };
                    }
                }

                _status = LlmStatus.Ready;
                return _availableModelNames.AsReadOnly();
            }
            catch (HttpRequestException ex)
            {
                _status = LlmStatus.Error;
                Health = Health with
                {
                    Status = HealthCheckStatus.Unhealthy,
                    LastError = ex.Message,
                    LastFailureAt = DateTimeOffset.UtcNow
                };
                return Array.Empty<string>();
            }
        }

        /// <summary>
        /// Downloads/pulls a model from the Ollama registry.
        /// </summary>
        /// <param name="modelName">Model name to pull (e.g., "llama3:8b").</param>
        /// <param name="progressCallback">Optional callback for pull progress.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        public async Task PullModelAsync(
            string modelName,
            Action<string>? progressCallback = null,
            CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();
            ArgumentException.ThrowIfNullOrWhiteSpace(modelName);

            var request = new { name = modelName };
            var content = new StringContent(
                JsonSerializer.Serialize(request),
                Encoding.UTF8,
                "application/json");

            var response = await _httpClient.PostAsync(
                $"{_baseUrl}/api/pull", content, cancellationToken);
            response.EnsureSuccessStatusCode();

            var responseStream = await response.Content.ReadAsStreamAsync(cancellationToken);
            using var reader = new StreamReader(responseStream);

            while (!reader.EndOfStream)
            {
                cancellationToken.ThrowIfCancellationRequested();
                var line = await reader.ReadLineAsync(cancellationToken);
                if (string.IsNullOrEmpty(line)) continue;

                try
                {
                    using var lineDoc = JsonDocument.Parse(line);
                    if (lineDoc.RootElement.TryGetProperty("status", out var status))
                    {
                        progressCallback?.Invoke(status.GetString() ?? "");
                    }
                }
                catch { /* Skip malformed lines */ }
            }
        }

        /// <summary>
        /// Deletes a model from the local Ollama instance.
        /// </summary>
        /// <param name="modelName">Model name to delete.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        public async Task DeleteModelAsync(string modelName, CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();
            ArgumentException.ThrowIfNullOrWhiteSpace(modelName);

            var request = new { name = modelName };
            var content = new StringContent(
                JsonSerializer.Serialize(request),
                Encoding.UTF8,
                "application/json");

            var requestMessage = new HttpRequestMessage(HttpMethod.Delete, $"{_baseUrl}/api/delete")
            {
                Content = content
            };

            var response = await _httpClient.SendAsync(requestMessage, cancellationToken);
            response.EnsureSuccessStatusCode();

            _modelCache.TryRemove(modelName, out _);
            lock (_availableModelNames)
            {
                _availableModelNames.Remove(modelName);
            }
        }

        /// <summary>
        /// Gets detailed information about a specific model.
        /// </summary>
        /// <param name="modelName">Model name.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        /// <returns>Model information dictionary.</returns>
        public async Task<IReadOnlyDictionary<string, string>> ShowModelInfoAsync(
            string modelName,
            CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();
            ArgumentException.ThrowIfNullOrWhiteSpace(modelName);

            var request = new { name = modelName };
            var content = new StringContent(
                JsonSerializer.Serialize(request),
                Encoding.UTF8,
                "application/json");

            var response = await _httpClient.PostAsync(
                $"{_baseUrl}/api/show", content, cancellationToken);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync(cancellationToken);
            using var doc = JsonDocument.Parse(json);

            var info = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (var prop in doc.RootElement.EnumerateObject())
            {
                info[prop.Name] = prop.Value.ToString();
            }

            return info;
        }

        /// <inheritdoc/>
        public async Task<StructuredOutput<T>> InferStructuredAsync<T>(
            string prompt,
            string? systemPrompt,
            string? jsonSchema,
            PromptContext context,
            CancellationToken cancellationToken = default) where T : class
        {
            ThrowIfDisposed();

            var jsonInstruction = !string.IsNullOrEmpty(jsonSchema)
                ? $"\n\nRespond ONLY with valid JSON matching this schema:\n{jsonSchema}\n"
                : "\n\nRespond ONLY with valid JSON.\n";

            var fullPrompt = prompt + jsonInstruction;

            var chatMessages = new List<ChatMessage>();
            if (!string.IsNullOrEmpty(systemPrompt))
                chatMessages.Add(ChatMessage.System(systemPrompt));
            chatMessages.Add(ChatMessage.User(fullPrompt));

            var response = await ChatCompletionAsync(chatMessages, context, cancellationToken);
            return StructuredOutputParser.ParseJson<T>(response);
        }

        /// <inheritdoc/>
        public async IAsyncEnumerable<StreamingToken> StreamAsync(
            IReadOnlyList<ChatMessage> messages,
            PromptContext context,
            [EnumeratorCancellation] CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();

            _currentCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);

            try
            {
                var model = GetModelForContext(context);
                var request = BuildChatRequest(messages, model, stream: true);

                var httpContent = new StringContent(
                    JsonSerializer.Serialize(request),
                    Encoding.UTF8,
                    "application/json");

                var httpRequest = new HttpRequestMessage(HttpMethod.Post, $"{_baseUrl}/api/chat")
                {
                    Content = httpContent
                };

                var response = await _httpClient.SendAsync(
                    httpRequest,
                    HttpCompletionOption.ResponseHeadersRead,
                    _currentCts.Token);

                response.EnsureSuccessStatusCode();

                var stream = await response.Content.ReadAsStreamAsync(_currentCts.Token);
                using var reader = new StreamReader(stream);

                while (!reader.EndOfStream)
                {
                    _currentCts.Token.ThrowIfCancellationRequested();
                    var line = await reader.ReadLineAsync(_currentCts.Token);
                    if (string.IsNullOrEmpty(line)) continue;

                    string? ollamaText = null;
                    bool ollamaDone = false;
                    try
                    {
                        using var lineDoc = JsonDocument.Parse(line);
                        var root = lineDoc.RootElement;

                        if (root.TryGetProperty("message", out var message) &&
                            message.TryGetProperty("content", out var content))
                        {
                            ollamaText = content.GetString() ?? "";
                            ollamaDone = root.TryGetProperty("done", out var doneProp) &&
                                       doneProp.GetBoolean();
                        }
                    }
                    catch { /* Skip malformed lines */ }

                    if (!string.IsNullOrEmpty(ollamaText))
                    {
                        yield return new StreamingToken
                        {
                            Text = ollamaText,
                            IsFinal = ollamaDone,
                            FinishReason = ollamaDone ? FinishReason.StopToken : default
                        };
                    }

                    if (ollamaDone) break;
                }
            }
            finally
            {
                _currentCts?.Dispose();
                _currentCts = null;
            }
        }

        /// <inheritdoc/>
        public async Task<EmbeddingResult> GetEmbeddingAsync(
            string text,
            EmbeddingModel model = EmbeddingModel.NomicEmbed,
            CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();

            var embeddingModel = model switch
            {
                EmbeddingModel.NomicEmbed => "nomic-embed-text",
                EmbeddingModel.AllMiniLM => "all-minilm",
                EmbeddingModel.TextEmbedding3Small => "nomic-embed-text",
                EmbeddingModel.TextEmbedding3Large => "nomic-embed-text",
                _ => "nomic-embed-text"
            };

            var request = new
            {
                model = embeddingModel,
                prompt = text
            };

            var content = new StringContent(
                JsonSerializer.Serialize(request),
                Encoding.UTF8,
                "application/json");

            var response = await _httpClient.PostAsync(
                $"{_baseUrl}/api/embeddings", content, cancellationToken);
            response.EnsureSuccessStatusCode();

            var responseJson = await response.Content.ReadAsStringAsync(cancellationToken);
            using var doc = JsonDocument.Parse(responseJson);

            float[] embedding = Array.Empty<float>();
            if (doc.RootElement.TryGetProperty("embedding", out var embeddingProp))
            {
                var values = new List<float>();
                foreach (var val in embeddingProp.EnumerateArray())
                    values.Add(val.GetSingle());
                embedding = values.ToArray();
            }

            return new EmbeddingResult
            {
                Vector = new EmbeddingVector
                {
                    Dimensions = embedding.Length,
                    Values = embedding,
                    Text = text,
                    Model = embeddingModel
                },
                Model = embeddingModel
            };
        }

        /// <inheritdoc/>
        public int EstimateTokens(string text)
        {
            if (string.IsNullOrEmpty(text)) return 0;
            return (int)Math.Ceiling(text.Length / 4.0);
        }

        /// <inheritdoc/>
        public ModelInfo? GetModelInfo(string modelId)
        {
            _modelCache.TryGetValue(modelId, out var info);
            return info;
        }

        /// <inheritdoc/>
        public async Task<bool> IsAvailableAsync(CancellationToken cancellationToken = default)
        {
            if (_disposed) return false;
            try
            {
                var response = await _httpClient.GetAsync(
                    $"{_baseUrl}/api/tags", cancellationToken);
                return response.IsSuccessStatusCode;
            }
            catch
            {
                return false;
            }
        }

        /// <inheritdoc/>
        public void CancelCurrentInference()
        {
            _currentCts?.Cancel();
        }

        /// <inheritdoc/>
        public async Task WarmUpAsync(CancellationToken cancellationToken = default)
        {
            _status = LlmStatus.WarmingUp;
            try
            {
                await DiscoverModelsAsync(cancellationToken);
                if (_availableModelNames.Count > 0)
                    _status = LlmStatus.Ready;
                else
                    _status = LlmStatus.Error;
            }
            catch
            {
                _status = LlmStatus.Error;
            }
        }

        /// <inheritdoc/>
        public Task ShutdownAsync()
        {
            _status = LlmStatus.Unavailable;
            _modelCache.Clear();
            return Task.CompletedTask;
        }

        /// <inheritdoc/>
        public async Task<HealthCheckStatus> CheckHealthAsync(CancellationToken cancellationToken = default)
        {
            if (_disposed) return HealthCheckStatus.Unhealthy;

            try
            {
                var response = await _httpClient.GetAsync(
                    $"{_baseUrl}/api/tags", cancellationToken);

                if (response.IsSuccessStatusCode)
                {
                    Health = Health with
                    {
                        Status = HealthCheckStatus.Healthy,
                        LastCheckedAt = DateTimeOffset.UtcNow
                    };
                    return HealthCheckStatus.Healthy;
                }

                Health = Health with
                {
                    Status = HealthCheckStatus.Unhealthy,
                    LastCheckedAt = DateTimeOffset.UtcNow,
                    LastError = $"HTTP {(int)response.StatusCode}"
                };
                return HealthCheckStatus.Unhealthy;
            }
            catch (Exception ex)
            {
                Health = Health with
                {
                    Status = HealthCheckStatus.Unhealthy,
                    LastCheckedAt = DateTimeOffset.UtcNow,
                    LastError = ex.Message
                };
                return HealthCheckStatus.Unhealthy;
            }
        }

        /// <summary>
        /// Sends a chat completion request without streaming.
        /// </summary>
        /// <param name="messages">Chat messages.</param>
        /// <param name="context">Request context.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        /// <returns>The generated response text.</returns>
        public async Task<string> ChatCompletionAsync(
            IReadOnlyList<ChatMessage> messages,
            PromptContext? context = null,
            CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();

            var model = context != null ? GetModelForContext(context) : _defaultModel;
            var request = BuildChatRequest(messages, model, stream: false);

            var content = new StringContent(
                JsonSerializer.Serialize(request),
                Encoding.UTF8,
                "application/json");

            var response = await _httpClient.PostAsync(
                $"{_baseUrl}/api/chat", content, cancellationToken);
            response.EnsureSuccessStatusCode();

            var responseJson = await response.Content.ReadAsStringAsync(cancellationToken);
            using var doc = JsonDocument.Parse(responseJson);

            if (doc.RootElement.TryGetProperty("message", out var message) &&
                message.TryGetProperty("content", out var contentProp))
            {
                Interlocked.Increment(ref _totalRequests);
                return contentProp.GetString() ?? "";
            }

            return "";
        }

        /// <summary>
        /// Generates text using the /api/generate endpoint.
        /// </summary>
        /// <param name="prompt">The prompt text.</param>
        /// <param name="model">Model name (uses default if null).</param>
        /// <param name="stream">Whether to stream the response.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        /// <returns>Generated text.</returns>
        public async Task<string> GenerateAsync(
            string prompt,
            string? model = null,
            bool stream = false,
            CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();

            var request = new
            {
                model = model ?? _defaultModel,
                prompt = prompt,
                stream = stream,
                options = new
                {
                    temperature = 0.7,
                    top_p = 0.9,
                    top_k = 40
                }
            };

            var content = new StringContent(
                JsonSerializer.Serialize(request),
                Encoding.UTF8,
                "application/json");

            var response = await _httpClient.PostAsync(
                $"{_baseUrl}/api/generate", content, cancellationToken);
            response.EnsureSuccessStatusCode();

            var responseJson = await response.Content.ReadAsStringAsync(cancellationToken);
            using var doc = JsonDocument.Parse(responseJson);

            if (doc.RootElement.TryGetProperty("response", out var responseProp))
            {
                Interlocked.Increment(ref _totalRequests);
                return responseProp.GetString() ?? "";
            }

            return "";
        }

        /// <summary>
        /// Sets the default model for subsequent requests.
        /// </summary>
        /// <param name="modelName">Model name to use as default.</param>
        public void SetDefaultModel(string modelName)
        {
            ArgumentException.ThrowIfNullOrWhiteSpace(modelName);
            _defaultModel = modelName;
        }

        /// <inheritdoc/>
        public void Dispose()
        {
            if (_disposed) return;
            _disposed = true;
            _currentCts?.Cancel();
            _currentCts?.Dispose();
            _modelCache.Clear();

            if (_ownsHttpClient)
                _httpClient.Dispose();
        }

        // ─── Private Helpers ───────────────────────────────────────────────

        private string GetModelForContext(PromptContext context)
        {
            if (context.ExtraParameters?.ContainsKey("model") == true)
                return context.ExtraParameters["model"]?.ToString() ?? _defaultModel;

            if (context.TaskType == LlmTaskType.EmbeddingGeneration)
                return "nomic-embed-text";

            if (context.TaskType == LlmTaskType.CodeGeneration && _modelCache.ContainsKey("codellama:13b"))
                return "codellama:13b";

            return _defaultModel;
        }

        private object BuildChatRequest(
            IReadOnlyList<ChatMessage> messages,
            string model,
            bool stream)
        {
            var formattedMessages = messages.Select(m => new
            {
                role = m.Role switch
                {
                    MessageRole.System => "system",
                    MessageRole.User => "user",
                    MessageRole.Assistant => "assistant",
                    _ => "user"
                },
                content = m.Content
            }).ToList();

            return new
            {
                model = model,
                messages = formattedMessages,
                stream = stream,
                options = new
                {
                    temperature = 0.7,
                    top_p = 0.9,
                    top_k = 40,
                    num_predict = 512
                }
            };
        }

        private void ThrowIfDisposed()
        {
            ObjectDisposedException.ThrowIf(_disposed, this);
        }
    }

    #endregion
    // =========================================================================

    // =========================================================================
    #region OpenAiProvider

    /// <summary>
    /// LLM inference provider using the OpenAI API.
    /// Supports chat completions, function calling, streaming via SSE, structured output,
    /// embeddings, vision, rate limit handling, and Azure OpenAI integration.
    /// </summary>
    public sealed class OpenAiProvider : ILlmInferenceProvider
    {
        private readonly HttpClient _httpClient;
        private readonly string _apiKey;
        private readonly string _baseUrl;
        private readonly bool _ownsHttpClient;
        private volatile bool _disposed;
        private volatile LlmStatus _status = LlmStatus.Unavailable;
        private readonly ConcurrentDictionary<string, ModelInfo> _modelCache;
        private readonly string _defaultModel;
        private readonly bool _isAzureEndpoint;
        private readonly string? _azureDeploymentName;
        private readonly string? _azureApiVersion;
        private CancellationTokenSource? _currentCts;
        private long _totalTokensGenerated;
        private long _totalRequests;
        private readonly object _rateLimitLock = new();
        private DateTimeOffset _rateLimitResetTime = DateTimeOffset.MinValue;
        private int _remainingRequests;
        private int _remainingTokens;

        /// <inheritdoc/>
        public string ProviderName => "OpenAI";

        /// <inheritdoc/>
        public bool RequiresNetwork => true;

        /// <inheritdoc/>
        public LlmStatus Status => _status;

        /// <inheritdoc/>
        public LlmProviderMode Mode => _isAzureEndpoint ? LlmProviderMode.RemoteAzure : LlmProviderMode.RemoteOpenAI;

        /// <inheritdoc/>
        public IReadOnlyList<ModelInfo> AvailableModels =>
            _modelCache.Values.ToList().AsReadOnly();

        /// <inheritdoc/>
        public ProviderHealth Health { get; private set; } = new() { ProviderName = "OpenAI" };

        /// <summary>Total tokens generated since initialization.</summary>
        public long TotalTokensGenerated => Interlocked.Read(ref _totalTokensGenerated);

        /// <summary>
        /// Initializes a new OpenAI provider.
        /// </summary>
        /// <param name="apiKey">OpenAI API key.</param>
        /// <param name="defaultModel">Default model ID.</param>
        /// <param name="baseUrl">Base API URL (overrides for Azure).</param>
        /// <param name="isAzure">Whether this is an Azure OpenAI endpoint.</param>
        /// <param name="azureDeploymentName">Azure deployment name.</param>
        /// <param name="azureApiVersion">Azure API version.</param>
        /// <param name="httpClient">Optional shared HttpClient.</param>
        public OpenAiProvider(
            string apiKey,
            string defaultModel = "gpt-4o-mini",
            string? baseUrl = null,
            bool isAzure = false,
            string? azureDeploymentName = null,
            string? azureApiVersion = null,
            HttpClient? httpClient = null)
        {
            _apiKey = apiKey ?? throw new ArgumentNullException(nameof(apiKey));
            _defaultModel = defaultModel ?? "gpt-4o-mini";
            _isAzureEndpoint = isAzure;
            _azureDeploymentName = azureDeploymentName;
            _azureApiVersion = azureApiVersion ?? "2024-02-15-preview";
            _modelCache = new ConcurrentDictionary<string, ModelInfo>(StringComparer.OrdinalIgnoreCase);

            if (isAzure)
            {
                if (string.IsNullOrWhiteSpace(baseUrl))
                    throw new ArgumentException("Azure OpenAI base URL is required.", nameof(baseUrl));
                _baseUrl = Synapse.Core.Security.UrlSecurity.ValidateOutboundUri(baseUrl.TrimEnd('/')).ToString().TrimEnd('/');
            }
            else
            {
                _baseUrl = Synapse.Core.Security.UrlSecurity.ValidateOutboundUri(
                    (baseUrl ?? "https://api.openai.com/v1").TrimEnd('/')).ToString().TrimEnd('/');
            }

            if (httpClient != null)
            {
                _httpClient = httpClient;
                _ownsHttpClient = false;
            }
            else
            {
                _httpClient = Synapse.Core.Security.UrlSecurity.CreateSafeHttpClient(TimeSpan.FromSeconds(180));
                _ownsHttpClient = true;
            }

            InitializeModelCache();
            _status = LlmStatus.Ready;
        }

        /// <inheritdoc/>
        public async Task<StructuredOutput<T>> InferStructuredAsync<T>(
            string prompt,
            string? systemPrompt,
            string? jsonSchema,
            PromptContext context,
            CancellationToken cancellationToken = default) where T : class
        {
            ThrowIfDisposed();

            var messages = new List<object>();
            if (!string.IsNullOrEmpty(systemPrompt))
                messages.Add(new { role = "system", content = systemPrompt });

            var userContent = !string.IsNullOrEmpty(jsonSchema)
                ? $"{prompt}\n\nRespond ONLY with valid JSON matching this schema:\n{jsonSchema}"
                : $"{prompt}\n\nRespond ONLY with valid JSON.";

            messages.Add(new { role = "user", content = userContent });

            var model = GetModelForContext(context);

            var requestBody = new
            {
                model = model,
                messages = messages.ToArray(),
                temperature = Math.Max(0, (context.ExtraParameters?.ContainsKey("temperature") == true
                    ? Convert.ToSingle(context.ExtraParameters["temperature"]) : 0.3f)),
                response_format = new { type = "json_object" },
                max_tokens = context.ExtraParameters?.ContainsKey("max_tokens") == true
                    ? Convert.ToInt32(context.ExtraParameters["max_tokens"]) : 4096
            };

            var responseJson = await SendRequestAsync("/chat/completions", requestBody, cancellationToken);
            using var doc = JsonDocument.Parse(responseJson);

            var content = "";
            if (doc.RootElement.TryGetProperty("choices", out var choices) &&
                choices.GetArrayLength() > 0)
            {
                var firstChoice = choices[0];
                if (firstChoice.TryGetProperty("message", out var msg) &&
                    msg.TryGetProperty("content", out var contentProp))
                {
                    content = contentProp.GetString() ?? "";
                }
            }

            Interlocked.Increment(ref _totalRequests);
            return StructuredOutputParser.ParseJson<T>(content);
        }

        /// <inheritdoc/>
        public async IAsyncEnumerable<StreamingToken> StreamAsync(
            IReadOnlyList<ChatMessage> messages,
            PromptContext context,
            [EnumeratorCancellation] CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();

            _currentCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);

            try
            {
                var formattedMessages = FormatMessagesForApi(messages, context);
                var model = GetModelForContext(context);

                var requestBody = new
                {
                    model = model,
                    messages = formattedMessages,
                    temperature = context.ExtraParameters?.ContainsKey("temperature") == true
                        ? Convert.ToSingle(context.ExtraParameters["temperature"]) : 0.7f,
                    max_tokens = context.ExtraParameters?.ContainsKey("max_tokens") == true
                        ? Convert.ToInt32(context.ExtraParameters["max_tokens"]) : 4096,
                    stream = true
                };

                var url = BuildUrl("/chat/completions");
                var request = new HttpRequestMessage(HttpMethod.Post, url)
                {
                    Content = new StringContent(
                        JsonSerializer.Serialize(requestBody),
                        Encoding.UTF8,
                        "application/json")
                };
                request.Headers.Add("Authorization", $"Bearer {_apiKey}");

                var response = await _httpClient.SendAsync(
                    request,
                    HttpCompletionOption.ResponseHeadersRead,
                    _currentCts.Token);

                HandleRateLimitHeaders(response);
                response.EnsureSuccessStatusCode();

                var stream = await response.Content.ReadAsStreamAsync(_currentCts.Token);
                using var reader = new StreamReader(stream);

                while (!reader.EndOfStream)
                {
                    _currentCts.Token.ThrowIfCancellationRequested();
                    var line = await reader.ReadLineAsync(_currentCts.Token);

                    if (string.IsNullOrEmpty(line)) continue;
                    if (!line.StartsWith("data: ")) continue;

                    var data = line.Substring(6).Trim();
                    if (data == "[DONE]") break;

                    string? openaiText = null;
                    FinishReason? openaiFinishReason = null;
                    try
                    {
                        using var lineDoc = JsonDocument.Parse(data);
                        var root = lineDoc.RootElement;

                        if (root.TryGetProperty("choices", out var choices) &&
                            choices.GetArrayLength() > 0)
                        {
                            var choice = choices[0];
                            if (choice.TryGetProperty("delta", out var delta) &&
                                delta.TryGetProperty("content", out var contentProp))
                            {
                                openaiText = contentProp.GetString() ?? "";
                                openaiFinishReason = choice.TryGetProperty("finish_reason", out var frProp)
                                    ? ParseFinishReason(frProp.GetString())
                                    : (FinishReason?)null;
                            }
                        }
                    }
                    catch { /* Skip malformed SSE lines */ }

                    if (!string.IsNullOrEmpty(openaiText))
                    {
                        yield return new StreamingToken
                        {
                            Text = openaiText,
                            IsFinal = openaiFinishReason.HasValue,
                            FinishReason = openaiFinishReason
                        };
                    }
                }

                Interlocked.Increment(ref _totalRequests);
            }
            finally
            {
                _currentCts?.Dispose();
                _currentCts = null;
            }
        }

        /// <inheritdoc/>
        public async Task<EmbeddingResult> GetEmbeddingAsync(
            string text,
            EmbeddingModel model = EmbeddingModel.TextEmbedding3Small,
            CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();

            var modelId = model switch
            {
                EmbeddingModel.TextEmbedding3Small => "text-embedding-3-small",
                EmbeddingModel.TextEmbedding3Large => "text-embedding-3-large",
                _ => "text-embedding-3-small"
            };

            var requestBody = new
            {
                model = modelId,
                input = text
            };

            var responseJson = await SendRequestAsync("/embeddings", requestBody, cancellationToken);
            using var doc = JsonDocument.Parse(responseJson);

            float[] embedding = Array.Empty<float>();
            int dimensions = 0;
            int promptTokens = 0;

            if (doc.RootElement.TryGetProperty("data", out var data) &&
                data.GetArrayLength() > 0)
            {
                var firstEmbedding = data[0];
                if (firstEmbedding.TryGetProperty("embedding", out var embeddingProp))
                {
                    var values = new List<float>();
                    foreach (var val in embeddingProp.EnumerateArray())
                        values.Add(val.GetSingle());
                    embedding = values.ToArray();
                    dimensions = embedding.Length;
                }
            }

            if (doc.RootElement.TryGetProperty("usage", out var usage) &&
                usage.TryGetProperty("prompt_tokens", out var ptProp))
            {
                promptTokens = ptProp.GetInt32();
            }

            Interlocked.Increment(ref _totalRequests);

            return new EmbeddingResult
            {
                Vector = new EmbeddingVector
                {
                    Dimensions = dimensions,
                    Values = embedding,
                    Text = text,
                    Model = modelId
                },
                Usage = new TokenUsage
                {
                    PromptTokens = promptTokens,
                    CompletionTokens = 0,
                    Model = modelId,
                    Provider = "OpenAI"
                },
                Model = modelId
            };
        }

        /// <inheritdoc/>
        public int EstimateTokens(string text)
        {
            if (string.IsNullOrEmpty(text)) return 0;
            // cl100k_base approximation: ~0.75 tokens per word, ~4 chars per token
            int wordCount = text.Split(new[] { ' ', '\t', '\n', '\r' },
                StringSplitOptions.RemoveEmptyEntries).Length;
            int charEstimate = text.Length / 4;
            return Math.Max(1, (int)(wordCount * 0.75 + charEstimate * 0.25));
        }

        /// <inheritdoc/>
        public ModelInfo? GetModelInfo(string modelId)
        {
            _modelCache.TryGetValue(modelId, out var info);
            return info;
        }

        /// <inheritdoc/>
        public async Task<bool> IsAvailableAsync(CancellationToken cancellationToken = default)
        {
            if (_disposed) return false;
            if (string.IsNullOrEmpty(_apiKey)) return false;

            try
            {
                var request = new HttpRequestMessage(HttpMethod.Get, BuildUrl("/models"));
                request.Headers.Add("Authorization", $"Bearer {_apiKey}");
                var response = await _httpClient.SendAsync(request, cancellationToken);
                return response.IsSuccessStatusCode;
            }
            catch
            {
                return false;
            }
        }

        /// <inheritdoc/>
        public void CancelCurrentInference()
        {
            _currentCts?.Cancel();
        }

        /// <inheritdoc/>
        public Task WarmUpAsync(CancellationToken cancellationToken = default)
        {
            _status = LlmStatus.WarmingUp;
            _status = LlmStatus.Ready;
            return Task.CompletedTask;
        }

        /// <inheritdoc/>
        public Task ShutdownAsync()
        {
            _status = LlmStatus.Unavailable;
            _modelCache.Clear();
            return Task.CompletedTask;
        }

        /// <inheritdoc/>
        public async Task<HealthCheckStatus> CheckHealthAsync(CancellationToken cancellationToken = default)
        {
            if (_disposed) return HealthCheckStatus.Unhealthy;

            try
            {
                var request = new HttpRequestMessage(HttpMethod.Get, BuildUrl("/models"));
                request.Headers.Add("Authorization", $"Bearer {_apiKey}");
                var response = await _httpClient.SendAsync(request, cancellationToken);

                if (response.IsSuccessStatusCode)
                {
                    Health = Health with
                    {
                        Status = HealthCheckStatus.Healthy,
                        LastCheckedAt = DateTimeOffset.UtcNow
                    };
                    return HealthCheckStatus.Healthy;
                }

                return HealthCheckStatus.Degraded;
            }
            catch
            {
                return HealthCheckStatus.Unhealthy;
            }
        }

        /// <summary>
        /// Sends a function/tool calling request.
        /// </summary>
        /// <param name="messages">Chat messages.</param>
        /// <param name="functions">Available functions.</param>
        /// <param name="context">Request context.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        /// <returns>The response with potential function calls.</returns>
        public async Task<LlmResponse> ChatWithFunctionsAsync(
            IReadOnlyList<ChatMessage> messages,
            IReadOnlyList<FunctionDefinition> functions,
            PromptContext context,
            CancellationToken cancellationToken = default)
        {
            ThrowIfDisposed();

            var formattedMessages = FormatMessagesForApi(messages, context);
            var model = GetModelForContext(context);

            var tools = functions.Select(f => new
            {
                type = "function",
                function = new
                {
                    name = f.Name,
                    description = f.Description,
                    parameters = new
                    {
                        type = "object",
                        properties = f.Parameters.ToDictionary(
                            p => p.Name,
                            p => new
                            {
                                type = p.Type,
                                description = p.Description
                            }),
                        required = f.Parameters.Where(p => p.Required).Select(p => p.Name).ToArray()
                    }
                }
            }).ToArray();

            var requestBody = new
            {
                model = model,
                messages = formattedMessages,
                tools = tools,
                temperature = 0.7f
            };

            var responseJson = await SendRequestAsync("/chat/completions", requestBody, cancellationToken);
            using var doc = JsonDocument.Parse(responseJson);

            string content = "";
            var functionCalls = new List<FunctionCall>();

            if (doc.RootElement.TryGetProperty("choices", out var choices) &&
                choices.GetArrayLength() > 0)
            {
                var choice = choices[0];
                if (choice.TryGetProperty("message", out var msg))
                {
                    if (msg.TryGetProperty("content", out var contentProp))
                        content = contentProp.GetString() ?? "";

                    if (msg.TryGetProperty("tool_calls", out var toolCalls))
                    {
                        foreach (var tc in toolCalls.EnumerateArray())
                        {
                            if (tc.TryGetProperty("function", out var func))
                            {
                                functionCalls.Add(new FunctionCall
                                {
                                    Name = func.TryGetProperty("name", out var nameProp)
                                        ? nameProp.GetString() ?? "" : "",
                                    Arguments = func.TryGetProperty("arguments", out var argsProp)
                                        ? argsProp.GetString() ?? "{}" : "{}"
                                });
                            }
                        }
                    }
                }
            }

            TokenUsage? usage = null;
            if (doc.RootElement.TryGetProperty("usage", out var usageProp))
            {
                int promptTokens = 0, completionTokens = 0;
                if (usageProp.TryGetProperty("prompt_tokens", out var pt))
                    promptTokens = pt.GetInt32();
                if (usageProp.TryGetProperty("completion_tokens", out var ct))
                    completionTokens = ct.GetInt32();

                usage = new TokenUsage
                {
                    PromptTokens = promptTokens,
                    CompletionTokens = completionTokens,
                    Model = model,
                    Provider = "OpenAI"
                };
            }

            Interlocked.Increment(ref _totalRequests);

            return new LlmResponse
            {
                Content = content,
                Model = model,
                Provider = "OpenAI",
                Usage = usage ?? new TokenUsage { Model = model, Provider = "OpenAI" },
                FinishReason = functionCalls.Count > 0 ? FinishReason.FunctionCall : FinishReason.StopToken,
                FunctionCalls = functionCalls.AsReadOnly()
            };
        }

        /// <inheritdoc/>
        public void Dispose()
        {
            if (_disposed) return;
            _disposed = true;
            _currentCts?.Cancel();
            _currentCts?.Dispose();
            _modelCache.Clear();
            if (_ownsHttpClient) _httpClient.Dispose();
        }

        // ─── Private Helpers ───────────────────────────────────────────────

        private void InitializeModelCache()
        {
            var models = new (string Id, string Name, int Context, int MaxOut, decimal InputCost, decimal OutputCost, bool Vision)[]
            {
                ("gpt-4o", "GPT-4o", 128000, 16384, 2.50m, 10.00m, true),
                ("gpt-4o-mini", "GPT-4o Mini", 128000, 16384, 0.15m, 0.60m, true),
                ("gpt-4-turbo", "GPT-4 Turbo", 128000, 4096, 10.00m, 30.00m, true),
                ("gpt-4", "GPT-4", 8192, 4096, 30.00m, 60.00m, false),
                ("gpt-3.5-turbo", "GPT-3.5 Turbo", 16385, 4096, 0.50m, 1.50m, false),
                ("text-embedding-3-small", "Text Embedding 3 Small", 8191, 0, 0.02m, 0m, false),
                ("text-embedding-3-large", "Text Embedding 3 Large", 8191, 0, 0.13m, 0m, false)
            };

            foreach (var m in models)
            {
                _modelCache[m.Id] = new ModelInfo
                {
                    ModelId = m.Id,
                    DisplayName = m.Name,
                    Provider = "OpenAI",
                    ContextWindow = m.Context,
                    MaxOutputTokens = m.MaxOut,
                    Tokenizer = TokenizerType.Tiktoken,
                    VocabularySize = 100000,
                    SupportsVision = m.Vision,
                    SupportsFunctionCalling = m.Id.StartsWith("gpt-4"),
                    SupportsEmbeddings = m.Id.Contains("embedding"),
                    InputCostPer1MTokens = m.InputCost,
                    OutputCostPer1MTokens = m.OutputCost
                };
            }
        }

        private string GetModelForContext(PromptContext context)
        {
            if (context.ExtraParameters?.ContainsKey("model") == true)
                return context.ExtraParameters["model"]?.ToString() ?? _defaultModel;

            return context.TaskType switch
            {
                LlmTaskType.CodeGeneration => "gpt-4o",
                LlmTaskType.GenomeCreation => "gpt-4o",
                LlmTaskType.BehaviorGeneration => "gpt-4o-mini",
                LlmTaskType.MaterialSuggestion => "gpt-4o-mini",
                LlmTaskType.EmbeddingGeneration => "text-embedding-3-small",
                LlmTaskType.NarrativeGeneration => "gpt-4o",
                _ => _defaultModel
            };
        }

        private string BuildUrl(string path)
        {
            if (_isAzureEndpoint)
            {
                return $"{_baseUrl}/openai/deployments/{_azureDeploymentName}{path}?api-version={_azureApiVersion}";
            }
            return $"{_baseUrl}{path}";
        }

        private object[] FormatMessagesForApi(IReadOnlyList<ChatMessage> messages, PromptContext context)
        {
            return messages.Select(m => (object)new
            {
                role = m.Role switch
                {
                    MessageRole.System => "system",
                    MessageRole.User => "user",
                    MessageRole.Assistant => "assistant",
                    MessageRole.Function => "function",
                    MessageRole.Tool => "tool",
                    _ => "user"
                },
                content = m.Content,
                name = m.Name
            }).ToArray();
        }

        private async Task<string> SendRequestAsync(
            string path,
            object requestBody,
            CancellationToken cancellationToken)
        {
            var url = BuildUrl(path);
            var request = new HttpRequestMessage(HttpMethod.Post, url)
            {
                Content = new StringContent(
                    JsonSerializer.Serialize(requestBody),
                    Encoding.UTF8,
                    "application/json")
            };
            request.Headers.Add("Authorization", $"Bearer {_apiKey}");

            var response = await _httpClient.SendAsync(request, cancellationToken);
            HandleRateLimitHeaders(response);

            if (response.StatusCode == (HttpStatusCode)429)
            {
                var retryAfter = response.Headers.RetryAfter?.Delta ?? TimeSpan.FromSeconds(5);
                await Task.Delay(retryAfter, cancellationToken);
                response = await _httpClient.SendAsync(request, cancellationToken);
            }

            response.EnsureSuccessStatusCode();
            return await response.Content.ReadAsStringAsync(cancellationToken);
        }

        private void HandleRateLimitHeaders(HttpResponseMessage response)
        {
            lock (_rateLimitLock)
            {
                if (response.Headers.TryGetValues("x-ratelimit-remaining-requests", out var reqValues))
                {
                    if (int.TryParse(reqValues.FirstOrDefault(), out var remaining))
                        _remainingRequests = remaining;
                }
                if (response.Headers.TryGetValues("x-ratelimit-reset-requests", out var resetValues))
                {
                    if (double.TryParse(resetValues.FirstOrDefault()?.Replace("s", ""),
                        NumberStyles.Float, CultureInfo.InvariantCulture, out var resetSeconds))
                    {
                        _rateLimitResetTime = DateTimeOffset.UtcNow.AddSeconds(resetSeconds);
                    }
                }
            }
        }

        private static FinishReason? ParseFinishReason(string? reason)
        {
            return reason switch
            {
                "stop" => FinishReason.StopToken,
                "length" => FinishReason.MaxTokens,
                "content_filter" => FinishReason.ContentFilter,
                "function_call" => FinishReason.FunctionCall,
                "tool_calls" => FinishReason.FunctionCall,
                _ => null
            };
        }

        private void ThrowIfDisposed()
        {
            ObjectDisposedException.ThrowIf(_disposed, this);
        }
    }

    #endregion
