            }
            catch { return HealthCheckStatus.Unhealthy; }
        }

        /// <inheritdoc/>
        public void Dispose()
        {
            if (_disposed) return;
            _disposed = true;
            _currentCts?.Cancel();
            _currentCts?.Dispose();
            if (_ownsHttpClient) _httpClient.Dispose();
        }

        // ─── Private Helpers ───────────────────────────────────────────────

