    #region LlmTokenizer

    /// <summary>
    /// BPE-based tokenizer supporting encoding, decoding, special tokens,
    /// truncation strategies, and batch operations. Used by the ONNX provider
    /// and for general token counting.
    /// </summary>
    public sealed class LlmTokenizer
    {
        private readonly Dictionary<string, int> _vocab;
        private readonly Dictionary<int, string> _reverseVocab;
        private readonly List<(string, string)> _bpeRanks;
        private readonly HashSet<string> _specialTokens;
        private readonly string _bosToken;
        private readonly string _eosToken;
        private readonly string _padToken;
        private readonly string _unkToken;
        private readonly int _vocabSize;
        private readonly object _encodeLock = new();

        /// <summary>Size of the vocabulary.</summary>
        public int VocabSize => _vocabSize;

        /// <summary>BOS token string.</summary>
        public string BosToken => _bosToken;

        /// <summary>EOS token string.</summary>
        public string EosToken => _eosToken;

        /// <summary>PAD token string.</summary>
        public string PadToken => _padToken;

        /// <summary>UNK token string.</summary>
        public string UnkToken => _unkToken;

        /// <summary>Number of BPE merge rules loaded.</summary>
        public int MergeCount => _bpeRanks.Count;

        /// <summary>
        /// Initializes a new tokenizer with a vocabulary and BPE merge rules.
        /// </summary>
        /// <param name="vocab">Vocabulary mapping token string to ID.</param>
        /// <param name="bpeRanks">BPE merge rules in priority order.</param>
        /// <param name="bosToken">Beginning-of-sequence token.</param>
        /// <param name="eosToken">End-of-sequence token.</param>
        /// <param name="padToken">Padding token.</param>
        /// <param name="unkToken">Unknown token.</param>
        public LlmTokenizer(
            Dictionary<string, int> vocab,
            List<(string, string)>? bpeRanks = null,
            string bosToken = "<s>",
            string eosToken = "</s>",
            string padToken = "<pad>",
            string unkToken = "<unk>")
        {
            _vocab = vocab ?? throw new ArgumentNullException(nameof(vocab));
            _reverseVocab = new Dictionary<int, string>();
            foreach (var (key, value) in _vocab)
                _reverseVocab[value] = key;

            _bpeRanks = bpeRanks ?? new List<(string, string)>();
            _bosToken = bosToken;
            _eosToken = eosToken;
            _padToken = padToken;
            _unkToken = unkToken;
            _vocabSize = _vocab.Count;

            _specialTokens = new HashSet<string>
            {
                _bosToken, _eosToken, _padToken, _unkToken,
                "<|system|>", "<|user|>", "<|assistant|>",
                "<|function|>", "<|tool|>"
            };
        }

        /// <summary>
        /// Loads a tokenizer from a vocabulary file (one token per line, tab-separated token and ID).
        /// </summary>
        /// <param name="vocabFilePath">Path to the vocabulary file.</param>
        /// <param name="bpeFilePath">Optional path to the BPE merges file.</param>
        /// <returns>A configured LlmTokenizer instance.</returns>
        public static LlmTokenizer LoadFromFile(string vocabFilePath, string? bpeFilePath = null)
        {
            ArgumentException.ThrowIfNullOrWhiteSpace(vocabFilePath);
            if (!File.Exists(vocabFilePath))
                throw new FileNotFoundException($"Vocabulary file not found: {vocabFilePath}");

            var vocab = new Dictionary<string, int>(StringComparer.Ordinal);
            foreach (var line in File.ReadLines(vocabFilePath))
            {
                if (string.IsNullOrWhiteSpace(line)) continue;
                var parts = line.Split('\t', 2);
                if (parts.Length == 2 && int.TryParse(parts[1], out var id))
                    vocab[parts[0]] = id;
                else if (parts.Length == 1)
                    vocab[parts[0]] = vocab.Count;
            }

            var bpeRanks = new List<(string, string)>();
            if (!string.IsNullOrEmpty(bpeFilePath) && File.Exists(bpeFilePath))
            {
                foreach (var line in File.ReadLines(bpeFilePath))
                {
                    if (string.IsNullOrWhiteSpace(line)) continue;
                    var parts = line.Split(' ', 2);
                    if (parts.Length == 2)
                        bpeRanks.Add((parts[0], parts[1]));
                }
            }

            return new LlmTokenizer(vocab, bpeRanks);
        }

        /// <summary>
        /// Encodes a string into token IDs.
        /// </summary>
        /// <param name="text">Input text.</param>
        /// <param name="addBos">Whether to prepend the BOS token.</param>
        /// <param name="addEos">Whether to append the EOS token.</param>
        /// <returns>Array of token IDs.</returns>
        public int[] Encode(string text, bool addBos = false, bool addEos = false)
        {
            if (string.IsNullOrEmpty(text))
            {
                var empty = new List<int>();
                if (addBos) empty.Add(_vocab.GetValueOrDefault(_bosToken, 0));
                if (addEos) empty.Add(_vocab.GetValueOrDefault(_eosToken, 1));
                return empty.ToArray();
            }

            var tokenIds = new List<int>();
            if (addBos) tokenIds.Add(_vocab.GetValueOrDefault(_bosToken, 0));

            var segments = text.Split(_specialTokens.ToArray(), StringSplitOptions.None);
            foreach (var segment in segments)
            {
                if (_specialTokens.Contains(segment))
                {
                    tokenIds.Add(_vocab.GetValueOrDefault(segment, _vocab.GetValueOrDefault(_unkToken, 3)));
                    continue;
                }

                var words = SegmentIntoWords(segment);
                foreach (var word in words)
                {
                    var bpeTokens = ApplyBpe(word);
                    foreach (var bpeToken in bpeTokens)
                    {
                        if (_vocab.TryGetValue(bpeToken, out var id))
                            tokenIds.Add(id);
                        else
                            tokenIds.Add(_vocab.GetValueOrDefault(_unkToken, 3));
                    }
                }
            }

            if (addEos) tokenIds.Add(_vocab.GetValueOrDefault(_eosToken, 1));
            return tokenIds.ToArray();
        }

        /// <summary>
        /// Decodes token IDs back to a string.
        /// </summary>
        /// <param name="tokenIds">Array of token IDs.</param>
        /// <param name="skipSpecial">Whether to skip special tokens in output.</param>
        /// <returns>Decoded string.</returns>
        public string Decode(int[] tokenIds, bool skipSpecial = true)
        {
            if (tokenIds == null || tokenIds.Length == 0) return string.Empty;

            var sb = new StringBuilder();
            foreach (var id in tokenIds)
            {
                if (_reverseVocab.TryGetValue(id, out var token))
                {
                    if (skipSpecial && _specialTokens.Contains(token)) continue;
                    sb.Append(token.Replace("Ġ", " ").Replace("Ċ", "\n"));
                }
            }
            return sb.ToString();
        }

        /// <summary>
        /// Counts the number of tokens in the given text.
        /// </summary>
        /// <param name="text">Input text.</param>
        /// <returns>Approximate token count.</returns>
        public int CountTokens(string text)
        {
            if (string.IsNullOrEmpty(text)) return 0;
            return Encode(text).Length;
        }

        /// <summary>
        /// Encodes multiple strings in a batch.
        /// </summary>
        /// <param name="texts">Input texts.</param>
        /// <param name="addBos">Whether to prepend BOS.</param>
        /// <param name="addEos">Whether to append EOS.</param>
        /// <param name="padToMaxLength">Whether to pad all sequences to the longest.</param>
        /// <returns>Batch of token ID arrays.</returns>
        public IReadOnlyList<int[]> BatchEncode(
            IReadOnlyList<string> texts,
            bool addBos = false,
            bool addEos = false,
            bool padToMaxLength = false)
        {
            var results = texts.Select(t => Encode(t, addBos, addEos)).ToList();

            if (padToMaxLength && results.Count > 0)
            {
                int maxLen = results.Max(r => r.Length);
                int padId = _vocab.GetValueOrDefault(_padToken, 0);
                results = results.Select(r =>
                {
                    if (r.Length < maxLen)
                    {
                        var padded = new int[maxLen];
                        Array.Copy(r, padded, r.Length);
                        for (int i = r.Length; i < maxLen; i++)
                            padded[i] = padId;
                        return padded;
                    }
                    return r;
                }).ToList();
            }

            return results;
        }

        /// <summary>
        /// Truncates token IDs to fit within a maximum length using the specified strategy.
        /// </summary>
        /// <param name="tokenIds">Input token IDs.</param>
        /// <param name="maxLength">Maximum allowed length.</param>
        /// <param name="strategy">Truncation strategy.</param>
        /// <returns>Truncated token IDs.</returns>
        public int[] Truncate(int[] tokenIds, int maxLength, TruncationStrategy strategy = TruncationStrategy.Tail)
        {
            if (tokenIds == null || tokenIds.Length <= maxLength) return tokenIds ?? Array.Empty<int>();

            return strategy switch
            {
                TruncationStrategy.Head => tokenIds.Skip(tokenIds.Length - maxLength).ToArray(),
                TruncationStrategy.Tail => tokenIds.Take(maxLength).ToArray(),
                TruncationStrategy.Middle => TruncateMiddle(tokenIds, maxLength),
                TruncationStrategy.Balanced => TruncateBalanced(tokenIds, maxLength),
                _ => tokenIds.Take(maxLength).ToArray()
            };
        }

        /// <summary>
        /// Adds a special token to the vocabulary.
        /// </summary>
        /// <param name="token">Token string to add.</param>
        /// <returns>The assigned token ID.</returns>
        public int AddSpecialToken(string token)
        {
            ArgumentException.ThrowIfNullOrWhiteSpace(token);
            if (_vocab.TryGetValue(token, out var existingId))
                return existingId;

            var newId = _vocab.Count;
            _vocab[token] = newId;
            _reverseVocab[newId] = token;
            _specialTokens.Add(token);
            return newId;
        }

        /// <summary>
        /// Gets the token ID for a specific token string.
        /// </summary>
        /// <param name="token">Token string.</param>
        /// <returns>Token ID, or -1 if not found.</returns>
        public int GetTokenId(string token)
        {
            return _vocab.TryGetValue(token, out var id) ? id : -1;
        }

        /// <summary>
        /// Gets the token string for a specific token ID.
        /// </summary>
        /// <param name="tokenId">Token ID.</param>
        /// <returns>Token string, or null if not found.</returns>
        public string? GetToken(int tokenId)
        {
            return _reverseVocab.TryGetValue(tokenId, out var token) ? token : null;
        }

        /// <summary>
        /// Analyzes token frequency in the given text.
        /// </summary>
        /// <param name="text">Input text.</param>
        /// <returns>Dictionary of token to frequency count.</returns>
        public IReadOnlyDictionary<string, int> AnalyzeFrequency(string text)
        {
            var tokenIds = Encode(text);
            var freq = new Dictionary<string, int>();
            foreach (var id in tokenIds)
            {
                var token = GetToken(id) ?? "<unk>";
                freq.TryGetValue(token, out var count);
                freq[token] = count + 1;
            }
            return freq;
        }

        // ─── Private Helpers ───────────────────────────────────────────────

        private static string[] SegmentIntoWords(string text)
        {
            var words = new List<string>();
            var current = new StringBuilder();

            foreach (var c in text)
            {
                if (char.IsLetterOrDigit(c))
                {
                    current.Append(c);
                }
                else
                {
                    if (current.Length > 0)
                    {
                        words.Add(current.ToString());
                        current.Clear();
                    }
                    words.Add(c.ToString());
                }
            }

            if (current.Length > 0)
                words.Add(current.ToString());

            return words.ToArray();
        }

        private List<string> ApplyBpe(string word)
        {
            if (string.IsNullOrEmpty(word)) return new List<string>();

            var chars = word.Select(c => c.ToString()).ToList();

            if (chars.Count == 1)
                return chars;

            for (int i = 0; i < chars.Count - 1; i++)
            {
                var pair = (chars[i], chars[i + 1]);
                int rank = _bpeRanks.IndexOf(pair);
                if (rank >= 0)
                {
                    var merged = pair.Item1 + pair.Item2;
                    chars[i] = merged;
                    chars.RemoveAt(i + 1);
                    i = Math.Max(-1, i - 2);
                }
            }

            return chars;
        }

        private static int[] TruncateMiddle(int[] tokenIds, int maxLength)
        {
            int half = maxLength / 2;
            var result = new int[maxLength];
            Array.Copy(tokenIds, 0, result, 0, half);
            Array.Copy(tokenIds, tokenIds.Length - (maxLength - half), result, half, maxLength - half);
            return result;
        }

        private static int[] TruncateBalanced(int[] tokenIds, int maxLength)
        {
            int headLen = (int)(maxLength * 0.6);
            int tailLen = maxLength - headLen;
            var result = new int[maxLength];
            Array.Copy(tokenIds, 0, result, 0, headLen);
            Array.Copy(tokenIds, tokenIds.Length - tailLen, result, headLen, tailLen);
            return result;
        }
    }

    #endregion
    // =========================================================================

    // =========================================================================
    #region PromptTemplateEngine

    /// <summary>
    /// Engine for constructing prompts from templates with variable substitution,
    /// conditional sections, loops, few-shot example injection, and chain-of-thought
    /// prompt construction.
    /// </summary>
    public sealed class PromptTemplateEngine
    {
        private readonly ConcurrentDictionary<string, string> _compiledTemplates;
        private readonly ConcurrentDictionary<string, string> _templateHashes;
        private readonly Random _rng;

        /// <summary>Number of compiled templates cached.</summary>
        public int CompiledTemplateCount => _compiledTemplates.Count;

        /// <summary>
        /// Initializes a new PromptTemplateEngine.
        /// </summary>
        public PromptTemplateEngine()
        {
            _compiledTemplates = new ConcurrentDictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            _templateHashes = new ConcurrentDictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            _rng = new Random();
        }

        /// <summary>
        /// Renders a template by replacing {{variable}} placeholders with values.
        /// </summary>
        /// <param name="template">Template string with {{variable}} placeholders.</param>
        /// <param name="variables">Dictionary of variable names to values.</param>
        /// <returns>Rendered string with variables substituted.</returns>
        public string Render(string template, IReadOnlyDictionary<string, string> variables)
        {
            if (string.IsNullOrEmpty(template)) return string.Empty;
            if (variables == null || variables.Count == 0) return template;

            var result = template;
            foreach (var (key, value) in variables)
            {
                result = result.Replace("{{" + key + "}}", value ?? "");
            }

            result = ProcessConditionals(result, variables);
            result = ProcessLoops(result, variables);

            return result;
        }

        /// <summary>
        /// Processes conditional sections: {{#if variable}}...{{/if}}.
        /// </summary>
        private string ProcessConditionals(string template, IReadOnlyDictionary<string, string> variables)
        {
            var pattern = @"\{\{#if\s+(\w+)\}\}([\s\S]*?)\{\{/if\}\}";
            return Regex.Replace(template, pattern, match =>
            {
                var varName = match.Groups[1].Value;
                var content = match.Groups[2].Value;
                if (variables.TryGetValue(varName, out var val) &&
                    !string.IsNullOrEmpty(val) &&
                    val != "false" && val != "0")
                    return content;
                return "";
            });
        }

        /// <summary>
        /// Processes loop sections: {{#each items}}...{{/each}} where items is comma-separated.
        /// </summary>
        private string ProcessLoops(string template, IReadOnlyDictionary<string, string> variables)
        {
            var pattern = @"\{\{#each\s+(\w+)\}\}([\s\S]*?)\{\{/each\}\}";
            return Regex.Replace(template, pattern, match =>
            {
                var varName = match.Groups[1].Value;
                var itemTemplate = match.Groups[2].Value;

                if (!variables.TryGetValue(varName, out var csvValue) || string.IsNullOrEmpty(csvValue))
                    return "";

                var items = csvValue.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
                var sb = new StringBuilder();

                foreach (var item in items)
                {
                    sb.Append(itemTemplate.Replace("{{this}}", item.Trim()));
                }

                return sb.ToString();
            });
        }

        /// <summary>
        /// Injects few-shot examples into the prompt.
        /// </summary>
        /// <param name="template">The template containing {{examples:count=N}}.</param>
        /// <param name="examples">Available examples to inject.</param>
        /// <param name="maxCount">Maximum number of examples to inject.</param>
        /// <returns>Template with examples injected.</returns>
        public string InjectExamples(
            string template,
            IReadOnlyList<(string Input, string Output)> examples,
            int maxCount = 3)
        {
            var pattern = @"\{\{examples:(?:count=(\d+))?\}\}";
            return Regex.Replace(template, pattern, match =>
            {
                int count = match.Groups[1].Success && int.TryParse(match.Groups[1].Value, out var c)
                    ? c : maxCount;
                count = Math.Min(count, examples.Count);

                var sb = new StringBuilder();
                for (int i = 0; i < count; i++)
                {
                    sb.AppendLine($"Example {i + 1}:");
                    sb.AppendLine($"Input: {examples[i].Input}");
                    sb.AppendLine($"Output: {examples[i].Output}");
                    sb.AppendLine();
                }
                return sb.ToString();
            });
        }

        /// <summary>
        /// Builds a chain-of-thought prompt from a question.
        /// </summary>
        /// <param name="question">The user's question.</param>
        /// <param name="context">Optional additional context.</param>
        /// <returns>A chain-of-thought prompt.</returns>
        public string BuildChainOfThoughtPrompt(string question, string? context = null)
        {
            var sb = new StringBuilder();
            sb.AppendLine("Let's approach this step by step.");
            if (!string.IsNullOrEmpty(context))
                sb.AppendLine($"Context: {context}");
            sb.AppendLine();
            sb.AppendLine($"Question: {question}");
            sb.AppendLine();
            sb.AppendLine("Step 1: Understand the problem.");
            sb.AppendLine("Step 2: Identify key information.");
            sb.AppendLine("Step 3: Apply relevant knowledge.");
            sb.AppendLine("Step 4: Formulate the answer.");
            sb.AppendLine();
            sb.AppendLine("Let me work through this:");
            return sb.ToString();
        }

        /// <summary>
        /// Builds a structured output prompt that instructs the LLM to return JSON.
        /// </summary>
        /// <param name="task">Description of what to generate.</param>
        /// <param name="jsonSchema">Expected JSON schema.</param>
        /// <returns>A structured output prompt.</returns>
        public string BuildStructuredOutputPrompt(string task, string jsonSchema)
        {
            return $"Task: {task}\n\n" +
                   $"You MUST respond with valid JSON that conforms to this schema:\n" +
                   $"```json\n{jsonSchema}\n```\n\n" +
                   $"Do not include any text outside the JSON response. " +
                   $"Do not use markdown code blocks. Return ONLY the raw JSON.";
        }

        /// <summary>
        /// Validates that a template has all required variables available.
        /// </summary>
        /// <param name="template">Template to validate.</param>
        /// <param name="availableVariables">Available variable names.</param>
        /// <returns>True if all required variables are available.</returns>
        public (bool IsValid, IReadOnlyList<string> MissingVariables) ValidateTemplate(
            string template,
            IEnumerable<string> availableVariables)
        {
            var required = ExtractVariables(template);
            var availableSet = new HashSet<string>(availableVariables, StringComparer.OrdinalIgnoreCase);
            var missing = required.Where(v => !availableSet.Contains(v)).ToList();
            return (missing.Count == 0, missing);
        }

        /// <summary>
        /// Extracts all variable names from a template.
        /// </summary>
        /// <param name="template">Template string.</param>
        /// <returns>List of variable names found in the template.</returns>
        public IReadOnlyList<string> ExtractVariables(string template)
        {
            if (string.IsNullOrEmpty(template)) return Array.Empty<string>();

            var matches = Regex.Matches(template, @"\{\{(\w+)\}\}");
            return matches.Select(m => m.Groups[1].Value)
                          .Distinct(StringComparer.OrdinalIgnoreCase)
                          .ToList();
        }

        /// <summary>
        /// Computes a hash of the template content for caching and versioning.
        /// </summary>
        /// <param name="template">Template content.</param>
        /// <returns>SHA-256 hash string.</returns>
        public static string ComputeTemplateHash(string template)
        {
            if (string.IsNullOrEmpty(template)) return "";
            using var sha = SHA256.Create();
            var bytes = sha.ComputeHash(Encoding.UTF8.GetBytes(template));
            return Convert.ToHexString(bytes).ToLowerInvariant();
        }

        /// <summary>
        /// Serializes scene context into a natural language prompt.
        /// </summary>
        /// <param name="scene">Scene description to serialize.</param>
        /// <returns>Natural language description of the scene.</returns>
        public string SerializeSceneContext(SceneDescription scene)
        {
            var sb = new StringBuilder();
            sb.AppendLine($"Scene: {scene.Name}");
            if (!string.IsNullOrEmpty(scene.Description))
                sb.AppendLine($"Description: {scene.Description}");

            if (scene.Entities != null && scene.Entities.Count > 0)
            {
                sb.AppendLine("\nEntities:");
                foreach (var entity in scene.Entities)
                {
                    sb.AppendLine($"  - {entity.Name} ({entity.Type})");
                    if (entity.Position.HasValue)
                        sb.AppendLine($"    Position: ({entity.Position.Value.X:F1}, {entity.Position.Value.Y:F1}, {entity.Position.Value.Z:F1})");
                    if (!string.IsNullOrEmpty(entity.Material))
                        sb.AppendLine($"    Material: {entity.Material}");
                }
            }

            if (scene.Relationships != null && scene.Relationships.Count > 0)
            {
                sb.AppendLine("\nRelationships:");
                foreach (var rel in scene.Relationships)
                    sb.AppendLine($"  - {rel.Source} --[{rel.Type}]--> {rel.Target}");
            }

            if (!string.IsNullOrEmpty(scene.Lighting))
                sb.AppendLine($"\nLighting: {scene.Lighting}");
            if (!string.IsNullOrEmpty(scene.Camera))
                sb.AppendLine($"Camera: {scene.Camera}");

            return sb.ToString();
        }
    }

    #endregion
    // =========================================================================

    // =========================================================================
    #region StructuredOutputParser

    /// <summary>
    /// Parses and validates structured output from LLM responses, including JSON
    /// extraction from markdown, schema validation, repair of common LLM errors,
    /// and extraction of domain-specific structures.
    /// </summary>
    public static class StructuredOutputParser
    {
        private static readonly Regex JsonBlockPattern = new(
            @"```(?:json)?\s*\n([\s\S]*?)\n\s*```",
            RegexOptions.Compiled);

        private static readonly Regex JsonObjectPattern = new(
            @"(\{[\s\S]*\})",
            RegexOptions.Compiled);

        private static readonly Regex TrailingCommaPattern = new(
            @",\s*([}\]])",
            RegexOptions.Compiled);

        private static readonly Regex UnquotedKeyPattern = new(
            @"(?<=[{,]\s*)(\w+)\s*:",
            RegexOptions.Compiled);

        /// <summary>
        /// Parses JSON from an LLM response, extracting it from markdown code blocks if necessary.
        /// </summary>
        /// <typeparam name="T">Target type to deserialize into.</typeparam>
        /// <param name="rawText">Raw LLM response text.</param>
        /// <returns>Parsed and validated result.</returns>
        public static StructuredOutput<T> ParseJson<T>(string rawText) where T : class
        {
            if (string.IsNullOrWhiteSpace(rawText))
                return StructuredOutput<T>.Fail("Empty response", rawText);

            var json = ExtractJson(rawText);
            if (string.IsNullOrEmpty(json))
                return StructuredOutput<T>.Fail("No JSON found in response", rawText);

            try
            {
                var options = new JsonSerializerOptions
                {
                    PropertyNameCaseInsensitive = true,
                    AllowTrailingCommas = true,
                    ReadCommentHandling = JsonCommentHandling.Skip
                };

                var data = JsonSerializer.Deserialize<T>(json, options);
                if (data == null)
                    return StructuredOutput<T>.Fail("Deserialization returned null", rawText);

                return StructuredOutput<T>.Ok(data, 0.9f, rawText);
            }
            catch (JsonException ex)
            {
                var repaired = RepairJson(json);
                try
                {
                    var data = JsonSerializer.Deserialize<T>(repaired);
                    if (data != null)
                        return StructuredOutput<T>.Ok(data, 0.7f, rawText);
                }
                catch { /* Repair failed */ }

                return StructuredOutput<T>.Fail($"JSON parse error: {ex.Message}", rawText);
            }
        }

        /// <summary>
        /// Extracts JSON string from LLM response text.
        /// </summary>
        /// <param name="text">Raw text.</param>
        /// <returns>Extracted JSON string, or null.</returns>
        public static string? ExtractJson(string text)
        {
            if (string.IsNullOrEmpty(text)) return null;

            // Try code block first
            var blockMatch = JsonBlockPattern.Match(text);
            if (blockMatch.Success)
                return blockMatch.Groups[1].Value.Trim();

            // Try finding a JSON object directly
            var objMatch = JsonObjectPattern.Match(text);
            if (objMatch.Success)
                return objMatch.Groups[1].Value;

            return null;
        }

        /// <summary>
        /// Attempts to repair common JSON errors in LLM output.
        /// </summary>
        /// <param name="json">Potentially broken JSON string.</param>
        /// <returns>Repaired JSON string.</returns>
        public static string RepairJson(string json)
        {
            if (string.IsNullOrEmpty(json)) return json;

            var result = json.Trim();

            // Remove markdown code block markers if present
            if (result.StartsWith("```"))
            {
                var firstNewline = result.IndexOf('\n');
                if (firstNewline >= 0)
                    result = result.Substring(firstNewline + 1);
                if (result.EndsWith("```"))
                    result = result.Substring(0, result.Length - 3);
                result = result.Trim();
            }

            // Fix trailing commas
            result = TrailingCommaPattern.Replace(result, "$1");

            // Fix unquoted keys (simple heuristic)
            result = UnquotedKeyPattern.Replace(result, match =>
            {
                var key = match.Groups[1].Value;
                if (key == "true" || key == "false" || key == "null" ||
                    double.TryParse(key, NumberStyles.Any, CultureInfo.InvariantCulture, out _))
                    return match.Value;
                return $"\"{key}\":";
            });

            // Ensure proper string escaping for common patterns
            result = result.Replace("\\\"", "\"").Replace("\"", "\\\"");

            return result;
        }

        /// <summary>
        /// Extracts a genome specification from natural language LLM output.
        /// </summary>
        /// <param name="text">LLM response describing a genome.</param>
        /// <returns>Extracted genome specification.</returns>
        public static StructuredOutput<GenomeSpecification> ExtractGenomeSpec(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return StructuredOutput<GenomeSpecification>.Fail("Empty input");

            var parameters = new Dictionary<string, object>();
            var name = "";
            var description = text;
            var type = "organoid";

            var nameMatch = Regex.Match(text, @"name[:\s]+[""']?([^""'\n]+)", RegexOptions.IgnoreCase);
            if (nameMatch.Success) name = nameMatch.Groups[1].Value.Trim();

            var typeMatch = Regex.Match(text, @"type[:\s]+[""']?(\w+)", RegexOptions.IgnoreCase);
            if (typeMatch.Success) type = typeMatch.Groups[1].Value.Trim();

            var paramMatches = Regex.Matches(text, @"(\w+)\s*[=:]\s*([\d.]+)", RegexOptions.IgnoreCase);
            foreach (Match m in paramMatches)
            {
                if (double.TryParse(m.Groups[2].Value, NumberStyles.Float, CultureInfo.InvariantCulture, out var val))
                    parameters[m.Groups[1].Value] = val;
            }

            var genome = new GenomeSpecification
            {
                Name = name,
                Description = description,
                Type = type,
                Parameters = parameters
            };

            return StructuredOutput<GenomeSpecification>.Ok(genome, 0.75f, text);
        }

        /// <summary>
        /// Extracts behavior tree nodes from LLM output.
        /// </summary>
        /// <param name="text">LLM response describing behavior.</param>
        /// <returns>List of extracted behavior tree nodes.</returns>
        public static StructuredOutput<IReadOnlyList<BehaviorTreeNode>> ExtractBehaviorTree(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return StructuredOutput<IReadOnlyList<BehaviorTreeNode>>.Fail("Empty input");

            var nodes = new List<BehaviorTreeNode>();

            var actionMatches = Regex.Matches(text, @"(?:action|do|perform)[:\s]+[""']?([^""'\n]+)",
                RegexOptions.IgnoreCase);
            foreach (Match m in actionMatches)
            {
                nodes.Add(new BehaviorTreeNode
                {
                    NodeType = "action",
                    Name = m.Groups[1].Value.Trim(),
                    Description = m.Groups[1].Value.Trim()
                });
            }

            var conditionMatches = Regex.Matches(text, @"(?:if|when|check|condition)[:\s]+[""']?([^""'\n]+)",
                RegexOptions.IgnoreCase);
            foreach (Match m in conditionMatches)
            {
                nodes.Add(new BehaviorTreeNode
                {
                    NodeType = "condition",
                    Name = m.Groups[1].Value.Trim(),
                    Description = m.Groups[1].Value.Trim()
                });
            }

            if (nodes.Count == 0)
            {
                nodes.Add(new BehaviorTreeNode
                {
                    NodeType = "sequence",
                    Name = "DefaultBehavior",
                    Description = text
                });
            }

            return StructuredOutput<IReadOnlyList<BehaviorTreeNode>>.Ok(nodes.AsReadOnly(), 0.6f, text);
        }

        /// <summary>
        /// Extracts material properties from natural language description.
        /// </summary>
        /// <param name="text">LLM response describing a material.</param>
        /// <returns>Extracted material properties.</returns>
        public static StructuredOutput<MaterialProperties> ExtractMaterialProperties(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return StructuredOutput<MaterialProperties>.Fail("Empty input");

            var material = new MaterialProperties { Name = "GeneratedMaterial" };

            var nameMatch = Regex.Match(text, @"(?:name|material)[:\s]+[""']?([^""'\n]+)", RegexOptions.IgnoreCase);
            if (nameMatch.Success) material = material with { Name = nameMatch.Groups[1].Value.Trim() };

            var colorMatch = Regex.Match(text, @"(?:color|colour)[:\s]+#?([0-9a-fA-F]{6})", RegexOptions.IgnoreCase);
            if (colorMatch.Success) material = material with { BaseColor = "#" + colorMatch.Groups[1].Value };

            var metallicMatch = Regex.Match(text, @"metallic[:\s]+([\d.]+)", RegexOptions.IgnoreCase);
            if (metallicMatch.Success && float.TryParse(metallicMatch.Groups[1].Value, NumberStyles.Float, CultureInfo.InvariantCulture, out var metallic))
                material = material with { Metallic = Math.Clamp(metallic, 0f, 1f) };

            var roughnessMatch = Regex.Match(text, @"roughness[:\s]+([\d.]+)", RegexOptions.IgnoreCase);
            if (roughnessMatch.Success && float.TryParse(roughnessMatch.Groups[1].Value, NumberStyles.Float, CultureInfo.InvariantCulture, out var roughness))
                material = material with { Roughness = Math.Clamp(roughness, 0f, 1f) };

            return StructuredOutput<MaterialProperties>.Ok(material, 0.7f, text);
        }

        /// <summary>
        /// Extracts entities and their types from text using pattern matching.
        /// </summary>
        /// <param name="text">Input text.</param>
        /// <returns>Extracted entities.</returns>
        public static IReadOnlyList<EntityExtractionResult> ExtractEntities(string text)
        {
            if (string.IsNullOrEmpty(text)) return Array.Empty<EntityExtractionResult>();

            var entities = new List<EntityExtractionResult>();

            // Extract quoted strings as entities
            var quoteMatches = Regex.Matches(text, @"[""']([^""']+)[""']");
            foreach (Match m in quoteMatches)
            {
                entities.Add(new EntityExtractionResult
                {
                    Text = m.Groups[1].Value,
                    Type = "quoted_string",
                    StartIndex = m.Groups[1].Index,
                    EndIndex = m.Groups[1].Index + m.Groups[1].Length,
                    Confidence = 0.9f
                });
            }

            // Extract numeric values
            var numberMatches = Regex.Matches(text, @"\b(\d+(?:\.\d+)?)\b");
            foreach (Match m in numberMatches)
            {
                entities.Add(new EntityExtractionResult
                {
                    Text = m.Groups[1].Value,
                    Type = "number",
                    StartIndex = m.Groups[1].Index,
                    EndIndex = m.Groups[1].Index + m.Groups[1].Length,
                    NormalizedValue = m.Groups[1].Value,
                    Confidence = 0.95f
                });
            }

            // Extract color references
            var colorMatches = Regex.Matches(text, @"#([0-9a-fA-F]{3,8})\b");
            foreach (Match m in colorMatches)
            {
                entities.Add(new EntityExtractionResult
                {
                    Text = "#" + m.Groups[1].Value,
                    Type = "color",
                    StartIndex = m.Groups[0].Index,
                    EndIndex = m.Groups[0].Index + m.Groups[0].Length,
                    Confidence = 0.95f
                });
            }

            return entities;
        }

        /// <summary>
        /// Validates a JSON string against a basic schema (property presence, types).
        /// </summary>
        /// <param name="json">JSON string to validate.</param>
        /// <param name="requiredProperties">Required property names.</param>
        /// <returns>Validation result.</returns>
        public static (bool IsValid, IReadOnlyList<string> Errors) ValidateJson(
            string json,
            IReadOnlyList<string>? requiredProperties = null)
        {
            var errors = new List<string>();

            try
            {
                using var doc = JsonDocument.Parse(json);

                if (requiredProperties != null)
                {
                    foreach (var prop in requiredProperties)
                    {
                        if (!doc.RootElement.TryGetProperty(prop, out _))
                            errors.Add($"Missing required property: '{prop}'");
                    }
                }
            }
            catch (JsonException ex)
            {
                errors.Add($"Invalid JSON: {ex.Message}");
            }

            return (errors.Count == 0, errors);
        }
    }

    #endregion
    // =========================================================================

    // =========================================================================
    #region LlmConversationManager

    /// <summary>
    /// Manages multi-turn conversations with LLM providers, including history,
    /// truncation, summarization, persistence, and search.
    /// </summary>
    public sealed class LlmConversationManager
    {
        private readonly ConcurrentDictionary<string, ConversationSession> _sessions;
        private readonly string _storagePath;
        private readonly int _maxTurnsBeforeTruncation;

        /// <summary>Number of active sessions.</summary>
        public int ActiveSessionCount => _sessions.Count;

        /// <summary>
        /// Initializes a new conversation manager.
        /// </summary>
        /// <param name="storagePath">Directory for persisting conversations.</param>
        /// <param name="maxTurnsBeforeTruncation">Max turns before auto-truncation.</param>
        public LlmConversationManager(
            string? storagePath = null,
            int maxTurnsBeforeTruncation = 50)
        {
            _sessions = new ConcurrentDictionary<string, ConversationSession>(StringComparer.OrdinalIgnoreCase);
            _storagePath = storagePath ?? Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                "GDNN", "Conversations");
            _maxTurnsBeforeTruncation = maxTurnsBeforeTruncation;

            if (!Directory.Exists(_storagePath))
                Directory.CreateDirectory(_storagePath);
        }

        /// <summary>
        /// Creates a new conversation session.
        /// </summary>
        /// <param name="systemPrompt">Optional system prompt.</param>
        /// <param name="sessionId">Optional custom session ID.</param>
        /// <returns>The session ID.</returns>
        public string CreateSession(string? systemPrompt = null, string? sessionId = null)
        {
            var id = sessionId ?? Guid.NewGuid().ToString("N");
            var session = new ConversationSession
            {
                Id = id,
                CreatedAt = DateTimeOffset.UtcNow,
                SystemPrompt = systemPrompt,
                Turns = new List<ConversationTurn>()
            };

            if (!string.IsNullOrEmpty(systemPrompt))
            {
                session.Turns.Add(new ConversationTurn
                {
                    UserMessage = ChatMessage.System(systemPrompt)
                });
            }

            _sessions[id] = session;
            return id;
        }

        /// <summary>
        /// Adds a user message and assistant response to the conversation.
        /// </summary>
        /// <param name="sessionId">Session ID.</param>
        /// <param name="userMessage">User's message.</param>
        /// <param name="assistantResponse">Assistant's response.</param>
        /// <param name="usage">Token usage for this turn.</param>
        /// <param name="provider">Provider that handled the request.</param>
        public void AddTurn(
            string sessionId,
            string userMessage,
            string assistantResponse,
            TokenUsage? usage = null,
            string? provider = null)
        {
            if (!_sessions.TryGetValue(sessionId, out var session))
                throw new ArgumentException($"Session '{sessionId}' not found.");

            session.Turns.Add(new ConversationTurn
            {
                UserMessage = ChatMessage.User(userMessage),
                AssistantMessage = ChatMessage.Assistant(assistantResponse),
                Usage = usage,
                Provider = provider,
                Timestamp = DateTimeOffset.UtcNow
            });

            if (session.Turns.Count > _maxTurnsBeforeTruncation)
            {
                TruncateSession(sessionId, session.Turns.Count - _maxTurnsBeforeTruncation);
            }
        }

        /// <summary>
        /// Gets the message history for a session.
        /// </summary>
        /// <param name="sessionId">Session ID.</param>
        /// <returns>List of chat messages.</returns>
        public IReadOnlyList<ChatMessage> GetHistory(string sessionId)
        {
            if (!_sessions.TryGetValue(sessionId, out var session))
                return Array.Empty<ChatMessage>();

            var messages = new List<ChatMessage>();
            if (!string.IsNullOrEmpty(session.SystemPrompt))
                messages.Add(ChatMessage.System(session.SystemPrompt));

            foreach (var turn in session.Turns)
            {
                messages.Add(turn.UserMessage);
                if (turn.AssistantMessage != null)
                    messages.Add(turn.AssistantMessage);
            }

            return messages;
        }

        /// <summary>
        /// Truncates old turns from the beginning of a session.
        /// </summary>
        /// <param name="sessionId">Session ID.</param>
        /// <param name="turnCount">Number of turns to remove.</param>
        public void TruncateSession(string sessionId, int turnCount)
        {
            if (!_sessions.TryGetValue(sessionId, out var session)) return;
            if (turnCount <= 0 || turnCount >= session.Turns.Count) return;

            session.Turns.RemoveRange(0, turnCount);
            session.IsTruncated = true;
        }

        /// <summary>
        /// Exports a conversation as JSON.
        /// </summary>
        /// <param name="sessionId">Session ID.</param>
        /// <returns>JSON string.</returns>
        public string ExportJson(string sessionId)
        {
            if (!_sessions.TryGetValue(sessionId, out var session))
                return "{}";

            return JsonSerializer.Serialize(session, new JsonSerializerOptions
            {
                WriteIndented = true
            });
        }

        /// <summary>
        /// Exports a conversation as Markdown.
        /// </summary>
        /// <param name="sessionId">Session ID.</param>
        /// <returns>Markdown string.</returns>
        public string ExportMarkdown(string sessionId)
        {
            if (!_sessions.TryGetValue(sessionId, out var session))
                return "";

            var sb = new StringBuilder();
            sb.AppendLine($"# Conversation {sessionId}");
            sb.AppendLine($"Created: {session.CreatedAt:yyyy-MM-dd HH:mm:ss}");
            sb.AppendLine();

            if (!string.IsNullOrEmpty(session.SystemPrompt))
            {
                sb.AppendLine($"**System:** {session.SystemPrompt}");
                sb.AppendLine();
            }

            foreach (var turn in session.Turns)
            {
                sb.AppendLine($"**User:** {turn.UserMessage.Content}");
                sb.AppendLine();
                if (turn.AssistantMessage != null)
                {
                    sb.AppendLine($"**Assistant:** {turn.AssistantMessage.Content}");
                    sb.AppendLine();
                }
                sb.AppendLine("---");
                sb.AppendLine();
            }

            return sb.ToString();
        }

        /// <summary>
        /// Saves a conversation to disk.
        /// </summary>
        /// <param name="sessionId">Session ID.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        public async Task SaveSessionAsync(string sessionId, CancellationToken cancellationToken = default)
        {
            if (!_sessions.TryGetValue(sessionId, out var session)) return;

            var filePath = Path.Combine(_storagePath, $"{sessionId}.json");
            var json = ExportJson(sessionId);
            await File.WriteAllTextAsync(filePath, json, cancellationToken);
        }

        /// <summary>
        /// Loads a conversation from disk.
        /// </summary>
        /// <param name="sessionId">Session ID.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        /// <returns>True if loaded successfully.</returns>
        public async Task<bool> LoadSessionAsync(string sessionId, CancellationToken cancellationToken = default)
        {
            var filePath = Path.Combine(_storagePath, $"{sessionId}.json");
            if (!File.Exists(filePath)) return false;

            var json = await File.ReadAllTextAsync(filePath, cancellationToken);
            using var doc = JsonDocument.Parse(json);

            var session = new ConversationSession
            {
                Id = sessionId,
                Turns = new List<ConversationTurn>()
            };

            if (doc.RootElement.TryGetProperty("createdAt", out var catProp))
                session.CreatedAt = DateTimeOffset.Parse(catProp.GetString() ?? "");
            if (doc.RootElement.TryGetProperty("systemPrompt", out var spProp))
                session.SystemPrompt = spProp.GetString();

            _sessions[sessionId] = session;
            return true;
        }

        /// <summary>
        /// Deletes a session.
        /// </summary>
        /// <param name="sessionId">Session ID.</param>
        /// <returns>True if the session was found and deleted.</returns>
        public bool DeleteSession(string sessionId)
        {
            if (_sessions.TryRemove(sessionId, out _))
            {
                var filePath = Path.Combine(_storagePath, $"{sessionId}.json");
                if (File.Exists(filePath)) File.Delete(filePath);
                return true;
            }
            return false;
        }

        /// <summary>
        /// Gets all active session IDs.
        /// </summary>
        public IReadOnlyList<string> GetSessionIds()
        {
            return _sessions.Keys.ToList().AsReadOnly();
        }
    }

    /// <summary>
    /// Represents a conversation session.
    /// </summary>
    internal sealed class ConversationSession
    {
        public string Id { get; set; } = string.Empty;
        public DateTimeOffset CreatedAt { get; set; }
        public string? SystemPrompt { get; set; }
        public List<ConversationTurn> Turns { get; set; } = new();
        public bool IsTruncated { get; set; }
    }

    #endregion
    // =========================================================================

    // =========================================================================
    #region LlmCache

    /// <summary>
    /// Multi-tier LLM response cache supporting exact-match and semantic similarity
    /// lookups, TTL expiration, LRU eviction, persistent storage, and compression.
    /// </summary>
    public sealed class LlmCache : IDisposable
    {
        private readonly ConcurrentDictionary<string, CacheEntry> _exactCache;
        private readonly List<CacheEntry> _semanticIndex;
        private readonly int _maxEntries;
        private readonly TimeSpan _defaultTtl;
        private readonly float _semanticThreshold;
        private readonly string? _persistentPath;
        private readonly object _semanticLock = new();
        private int _hitCount;
        private int _missCount;
        private int _evictionCount;
        private bool _disposed;

        /// <summary>Total cache hits.</summary>
        public int HitCount => _hitCount;

        /// <summary>Total cache misses.</summary>
        public int MissCount => _missCount;

        /// <summary>Total evictions.</summary>
        public int EvictionCount => _evictionCount;

        /// <summary>Cache hit rate as a percentage.</summary>
        public float HitRate =>
            (_hitCount + _missCount) > 0
                ? (float)_hitCount / (_hitCount + _missCount) * 100f
                : 0f;

        /// <summary>Current number of entries.</summary>
        public int Count => _exactCache.Count;

        /// <summary>
        /// Initializes a new LLM cache.
        /// </summary>
        /// <param name="maxEntries">Maximum cache entries before LRU eviction.</param>
        /// <param name="defaultTtl">Default time-to-live for entries.</param>
        /// <param name="semanticThreshold">Cosine similarity threshold for semantic cache hits (0-1).</param>
        /// <param name="persistentPath">Optional path for persistent cache storage.</param>
        public LlmCache(
            int maxEntries = 10000,
            TimeSpan? defaultTtl = null,
            float semanticThreshold = 0.95f,
            string? persistentPath = null)
        {
            _maxEntries = maxEntries;
            _defaultTtl = defaultTtl ?? TimeSpan.FromHours(1);
            _semanticThreshold = semanticThreshold;
            _persistentPath = persistentPath;
            _exactCache = new ConcurrentDictionary<string, CacheEntry>(StringComparer.OrdinalIgnoreCase);
            _semanticIndex = new List<CacheEntry>();

            if (!string.IsNullOrEmpty(persistentPath) && Directory.Exists(persistentPath))
            {
                LoadFromDisk();
            }
        }

        /// <summary>
        /// Stores a response in the cache.
        /// </summary>
        /// <param name="prompt">The original prompt.</param>
        /// <param name="response">The LLM response.</param>
        /// <param name="ttl">Optional custom TTL.</param>
        /// <param name="embedding">Optional embedding for semantic lookup.</param>
        public void Store(
            string prompt,
            LlmResponse response,
            TimeSpan? ttl = null,
            EmbeddingVector? embedding = null)
        {
            if (_disposed) return;

            var hash = ComputeHash(prompt);
            var entry = new CacheEntry
            {
                Response = response,
                PromptHash = hash,
                CreatedAt = DateTimeOffset.UtcNow,
                ExpiresAt = DateTimeOffset.UtcNow + (ttl ?? _defaultTtl),
                AccessCount = 0,
                SizeBytes = Encoding.UTF8.GetByteCount(response.Content),
                SemanticEmbedding = embedding
            };

            _exactCache[hash] = entry;

            if (embedding != null)
            {
                lock (_semanticLock)
                {
                    _semanticIndex.Add(entry);
                }
            }

            EvictIfNeeded();
        }

        /// <summary>
        /// Retrieves a cached response using exact match.
        /// </summary>
        /// <param name="prompt">The prompt to look up.</param>
        /// <returns>The cached response, or null if not found/expired.</returns>
        public LlmResponse? GetExact(string prompt)
        {
            if (_disposed || string.IsNullOrEmpty(prompt)) return null;

            var hash = ComputeHash(prompt);
            if (!_exactCache.TryGetValue(hash, out var entry)) return null;

            if (entry.IsInvalidated || DateTimeOffset.UtcNow > entry.ExpiresAt)
            {
                _exactCache.TryRemove(hash, out _);
                Interlocked.Increment(ref _missCount);
                return null;
            }

            Interlocked.Increment(ref _hitCount);
            var updated = entry with { AccessCount = entry.AccessCount + 1, LastAccessedAt = DateTimeOffset.UtcNow };
            _exactCache[hash] = updated;
            return entry.Response;
        }

        /// <summary>
        /// Retrieves a cached response using semantic similarity.
        /// </summary>
        /// <param name="queryEmbedding">Embedding of the query.</param>
        /// <returns>The best matching cached response, or null.</returns>
        public LlmResponse? GetSemantic(EmbeddingVector queryEmbedding)
        {
            if (_disposed || queryEmbedding.Values.Length == 0) return null;

            CacheEntry? bestMatch = null;
            float bestScore = 0f;

            lock (_semanticLock)
            {
                foreach (var entry in _semanticIndex)
                {
                    if (entry.IsInvalidated || DateTimeOffset.UtcNow > entry.ExpiresAt) continue;
                    if (entry.SemanticEmbedding == null) continue;

                    var score = ComputeCosineSimilarity(
                        queryEmbedding.Values, entry.SemanticEmbedding.Values);

                    if (score > bestScore && score >= _semanticThreshold)
                    {
                        bestScore = score;
                        bestMatch = entry;
                    }
                }
            }

            if (bestMatch != null)
            {
                Interlocked.Increment(ref _hitCount);
                return bestMatch.Response;
            }

            Interlocked.Increment(ref _missCount);
            return null;
        }

        /// <summary>
        /// Invalidates all cache entries for a specific model.
        /// </summary>
        /// <param name="model">Model name to invalidate.</param>
        public void InvalidateByModel(string model)
        {
            if (string.IsNullOrEmpty(model)) return;

            var keysToInvalidate = _exactCache
                .Where(kv => kv.Value.Response.Model == model)
                .Select(kv => kv.Key)
                .ToList();

            foreach (var key in keysToInvalidate)
            {
                if (_exactCache.TryGetValue(key, out var entry))
                {
                    _exactCache[key] = entry with { IsInvalidated = true };
                }
            }
        }

        /// <summary>
        /// Clears all cache entries.
        /// </summary>
        public void Clear()
        {
            _exactCache.Clear();
            lock (_semanticLock) { _semanticIndex.Clear(); }
        }

        /// <summary>
        /// Gets cache statistics.
        /// </summary>
        public CacheStatistics GetStatistics()
        {
            return new CacheStatistics
            {
                TotalEntries = _exactCache.Count,
                HitCount = _hitCount,
                MissCount = _missCount,
                EvictionCount = _evictionCount,
                HitRate = HitRate,
                TotalSizeBytes = _exactCache.Values.Sum(e => e.SizeBytes),
                SemanticIndexSize = _semanticIndex.Count
            };
        }

        /// <summary>
        /// Persists the cache to disk.
        /// </summary>
        public void PersistToDisk()
        {
            if (string.IsNullOrEmpty(_persistentPath)) return;
            if (!Directory.Exists(_persistentPath))
                Directory.CreateDirectory(_persistentPath);

            var filePath = Path.Combine(_persistentPath, "llm_cache.json");
            var entries = _exactCache.Values
                .Where(e => !e.IsInvalidated && DateTimeOffset.UtcNow <= e.ExpiresAt)
                .ToList();

            var json = JsonSerializer.Serialize(entries, new JsonSerializerOptions { WriteIndented = true });
            File.WriteAllText(filePath, json);
        }

        /// <summary>
        /// Computes cosine similarity between two vectors.
        /// </summary>
        public static float ComputeCosineSimilarity(float[] a, float[] b)
        {
            if (a == null || b == null || a.Length == 0 || a.Length != b.Length) return 0f;

            float dot = 0f, normA = 0f, normB = 0f;
            for (int i = 0; i < a.Length; i++)
            {
                dot += a[i] * b[i];
                normA += a[i] * a[i];
                normB += b[i] * b[i];
            }

            float denominator = MathF.Sqrt(normA) * MathF.Sqrt(normB);
            return denominator > 1e-10f ? dot / denominator : 0f;
        }

        /// <inheritdoc/>
        public void Dispose()
        {
            if (_disposed) return;
            _disposed = true;
            PersistToDisk();
        }

        private static string ComputeHash(string prompt)
        {
            using var sha = SHA256.Create();
            var bytes = sha.ComputeHash(Encoding.UTF8.GetBytes(prompt));
            return Convert.ToHexString(bytes).ToLowerInvariant();
        }

        private void EvictIfNeeded()
        {
            while (_exactCache.Count > _maxEntries)
            {
                var oldest = _exactCache.Values
                    .OrderBy(e => e.LastAccessedAt)
                    .FirstOrDefault();

                if (oldest != null)
                {
                    _exactCache.TryRemove(oldest.PromptHash, out _);
                    Interlocked.Increment(ref _evictionCount);
                }
                else break;
            }
        }

        private void LoadFromDisk()
        {
            try
            {
                var filePath = Path.Combine(_persistentPath!, "llm_cache.json");
                if (!File.Exists(filePath)) return;

                var json = File.ReadAllText(filePath);
                var entries = JsonSerializer.Deserialize<List<CacheEntry>>(json);
                if (entries != null)
                {
                    foreach (var entry in entries)
                    {
                        if (!entry.IsInvalidated && DateTimeOffset.UtcNow <= entry.ExpiresAt)
                            _exactCache[entry.PromptHash] = entry;
                    }
                }
            }
            catch { /* Best effort loading */ }
        }
    }

    /// <summary>
    /// Cache statistics.
    /// </summary>
    public record CacheStatistics
    {
        /// <summary>Total entries in cache.</summary>
        public int TotalEntries { get; init; }

        /// <summary>Total cache hits.</summary>
        public int HitCount { get; init; }

        /// <summary>Total cache misses.</summary>
        public int MissCount { get; init; }

        /// <summary>Total evictions.</summary>
        public int EvictionCount { get; init; }

        /// <summary>Hit rate percentage.</summary>
        public float HitRate { get; init; }

        /// <summary>Total size in bytes.</summary>
        public long TotalSizeBytes { get; init; }

        /// <summary>Semantic index size.</summary>
        public int SemanticIndexSize { get; init; }
    }

    #endregion
    // =========================================================================

    // =========================================================================
    #region LlmRateLimiter

    /// <summary>
    /// Advanced rate limiter for LLM requests supporting token bucket, sliding window,
    /// priority queuing, per-provider limits, and graceful degradation.
    /// </summary>
    public sealed class LlmRateLimiter
    {
        private readonly ConcurrentDictionary<string, TokenBucketState> _tokenBuckets;
        private readonly ConcurrentDictionary<string, SlidingWindowState> _slidingWindows;
        private readonly ConcurrentDictionary<string, PriorityQueue<RateLimitedRequest, int>> _priorityQueues;
        private readonly RateLimitConfig _globalConfig;
        private readonly int _globalMaxConcurrent;
        private int _globalActiveRequests;
        private readonly object _globalLock = new();

        /// <summary>Number of requests currently in flight globally.</summary>
        public int GlobalActiveRequests => _globalActiveRequests;

        /// <summary>
        /// Initializes a new rate limiter.
        /// </summary>
        /// <param name="globalConfig">Global rate limit configuration.</param>
        public LlmRateLimiter(RateLimitConfig? globalConfig = null)
        {
            _globalConfig = globalConfig ?? new RateLimitConfig();
            _globalMaxConcurrent = _globalConfig.MaxConcurrent;
            _tokenBuckets = new ConcurrentDictionary<string, TokenBucketState>(StringComparer.OrdinalIgnoreCase);
            _slidingWindows = new ConcurrentDictionary<string, SlidingWindowState>(StringComparer.OrdinalIgnoreCase);
            _priorityQueues = new ConcurrentDictionary<string, PriorityQueue<RateLimitedRequest, int>>(StringComparer.OrdinalIgnoreCase);
        }

        /// <summary>
        /// Checks whether a request to the specified provider is allowed.
        /// </summary>
        /// <param name="providerName">Provider name.</param>
        /// <param name="priority">Request priority.</param>
        /// <param name="estimatedTokens">Estimated tokens for this request.</param>
        /// <returns>True if the request is allowed.</returns>
        public bool IsAllowed(string providerName, RequestPriority priority, int estimatedTokens = 1)
        {
            lock (_globalLock)
            {
                if (_globalActiveRequests >= _globalMaxConcurrent)
                    return false;
            }

            if (_tokenBuckets.TryGetValue(providerName, out var bucket))
            {
                if (!bucket.TryConsume(estimatedTokens))
                    return false;
            }

            if (_slidingWindows.TryGetValue(providerName, out var window))
            {
                if (!window.TryRecord(DateTimeOffset.UtcNow))
                    return false;
            }

            return true;
        }

        /// <summary>
        /// Attempts to acquire a rate limit slot. Returns false if rate limited.
        /// </summary>
        /// <param name="providerName">Provider name.</param>
        /// <param name="priority">Request priority.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        /// <returns>True if slot acquired.</returns>
        public async Task<bool> AcquireAsync(
            string providerName,
            RequestPriority priority,
            CancellationToken cancellationToken = default)
        {
            var maxWait = TimeSpan.FromSeconds(30);
            var stopwatch = Stopwatch.StartNew();

            while (stopwatch.Elapsed < maxWait)
            {
                cancellationToken.ThrowIfCancellationRequested();

                if (IsAllowed(providerName, priority))
                {
                    Interlocked.Increment(ref _globalActiveRequests);
                    return true;
                }

                await Task.Delay(100, cancellationToken);
            }

            return false;
        }

        /// <summary>
        /// Releases a previously acquired rate limit slot.
        /// </summary>
        /// <param name="providerName">Provider name.</param>
        public void Release(string providerName)
        {
            Interlocked.Decrement(ref _globalActiveRequests);
        }

        /// <summary>
        /// Configures per-provider rate limits.
        /// </summary>
        /// <param name="providerName">Provider name.</param>
        /// <param name="config">Rate limit configuration.</param>
        public void ConfigureProvider(string providerName, RateLimitConfig config)
        {
            _tokenBuckets[providerName] = new TokenBucketState(
                config.TokensPerMinute, config.BurstSize, TimeSpan.FromMinutes(1));

            _slidingWindows[providerName] = new SlidingWindowState(
                config.RequestsPerMinute, TimeSpan.FromMinutes(1));
        }

        /// <summary>
        /// Gets the estimated wait time before a request would be allowed.
        /// </summary>
        /// <param name="providerName">Provider name.</param>
        /// <returns>Estimated wait time.</returns>
        public TimeSpan GetWaitTime(string providerName)
        {
            if (_tokenBuckets.TryGetValue(providerName, out var bucket))
                return bucket.EstimateWaitTime(1);
            return TimeSpan.Zero;
        }

        /// <summary>
        /// Resets rate limit state for a provider.
        /// </summary>
        /// <param name="providerName">Provider name.</param>
        public void ResetProvider(string providerName)
        {
            _tokenBuckets.TryRemove(providerName, out _);
            _slidingWindows.TryRemove(providerName, out _);
        }

        /// <summary>
        /// Gets current rate limit status for all providers.
        /// </summary>
        public IReadOnlyDictionary<string, RateLimitStatus> GetStatus()
        {
            var status = new Dictionary<string, RateLimitStatus>(StringComparer.OrdinalIgnoreCase);

            foreach (var (name, bucket) in _tokenBuckets)
            {
                status[name] = new RateLimitStatus
                {
                    ProviderName = name,
                    RemainingTokens = bucket.RemainingTokens,
                    TokensPerMinute = bucket.Capacity,
                    IsThrottled = bucket.RemainingTokens <= 0
                };
            }

            return status;
        }
    }

    /// <summary>
    /// Token bucket state for rate limiting.
    /// </summary>
    internal sealed class TokenBucketState
    {
        private readonly int _refillRate;
        private readonly int _capacity;
        private readonly TimeSpan _refillInterval;
        private double _tokens;
        private DateTimeOffset _lastRefill;
        private readonly object _lock = new();

        public int Capacity => _capacity;
        public int RemainingTokens => (int)_tokens;

        public TokenBucketState(int refillRate, int capacity, TimeSpan refillInterval)
        {
            _refillRate = refillRate;
            _capacity = capacity;
            _refillInterval = refillInterval;
            _tokens = capacity;
            _lastRefill = DateTimeOffset.UtcNow;
        }

        public bool TryConsume(int tokens)
        {
            lock (_lock)
            {
                Refill();
                if (_tokens >= tokens)
                {
                    _tokens -= tokens;
                    return true;
                }
                return false;
            }
        }

        public TimeSpan EstimateWaitTime(int tokens)
        {
            lock (_lock)
            {
                Refill();
                if (_tokens >= tokens) return TimeSpan.Zero;
                double deficit = tokens - _tokens;
                double seconds = deficit / _refillRate * _refillInterval.TotalSeconds;
                return TimeSpan.FromSeconds(Math.Ceiling(seconds));
            }
        }

        private void Refill()
        {
            var now = DateTimeOffset.UtcNow;
            var elapsed = now - _lastRefill;
            var intervals = (int)(elapsed.TotalMilliseconds / _refillInterval.TotalMilliseconds);
            if (intervals > 0)
            {
                _tokens = Math.Min(_capacity, _tokens + intervals * _refillRate);
                _lastRefill = now;
            }
        }
    }

    /// <summary>
    /// Sliding window rate limit state.
    /// </summary>
    internal sealed class SlidingWindowState
    {
        private readonly int _maxRequests;
        private readonly TimeSpan _windowSize;
        private readonly Queue<DateTimeOffset> _timestamps;
        private readonly object _lock = new();

        public SlidingWindowState(int maxRequests, TimeSpan windowSize)
        {
            _maxRequests = maxRequests;
            _windowSize = windowSize;
            _timestamps = new Queue<DateTimeOffset>();
        }

        public bool TryRecord(DateTimeOffset now)
        {
            lock (_lock)
            {
                var cutoff = now - _windowSize;
                while (_timestamps.Count > 0 && _timestamps.Peek() < cutoff)
                    _timestamps.Dequeue();

                if (_timestamps.Count < _maxRequests)
                {
                    _timestamps.Enqueue(now);
                    return true;
                }
                return false;
            }
        }
    }

    /// <summary>
    /// Rate limit status for a provider.
    /// </summary>
    public record RateLimitStatus
    {
        /// <summary>Provider name.</summary>
        public string ProviderName { get; init; } = string.Empty;

        /// <summary>Remaining tokens in the bucket.</summary>
        public int RemainingTokens { get; init; }

        /// <summary>Total token capacity.</summary>
        public int TokensPerMinute { get; init; }

        /// <summary>Whether the provider is currently throttled.</summary>
        public bool IsThrottled { get; init; }
    }

    /// <summary>
    /// A rate-limited request with priority.
    /// </summary>
    internal sealed class RateLimitedRequest
    {
        public string ProviderName { get; set; } = string.Empty;
        public RequestPriority Priority { get; set; }
        public int EstimatedTokens { get; set; }
        public DateTimeOffset QueuedAt { get; set; } = DateTimeOffset.UtcNow;
        public TaskCompletionSource<bool>? CompletionSource { get; set; }
    }

    #endregion
    // =========================================================================

    // =========================================================================
    #region LlmCostTracker

    /// <summary>
    /// Tracks LLM usage costs across providers, enforces budgets, generates reports,
    /// and provides cost optimization suggestions.
    /// </summary>
    public sealed class LlmCostTracker : IDisposable
    {
        private readonly ConcurrentBag<CostEntry> _entries;
        private readonly CostTrackerConfig _config;
        private readonly object _lock = new();
        private decimal _currentDailyCost;
        private decimal _currentMonthlyCost;
        private int _currentDailyTokens;
        private int _currentMonthlyTokens;
        private DateTimeOffset _lastDailyReset;
        private DateTimeOffset _lastMonthlyReset;
        private bool _disposed;

        /// <summary>Current daily cost in USD.</summary>
        public decimal CurrentDailyCost => _currentDailyCost;

        /// <summary>Current monthly cost in USD.</summary>
        public decimal CurrentMonthlyCost => _currentMonthlyCost;

        /// <summary>Total cost entries tracked.</summary>
        public int EntryCount => _entries.Count;

        /// <summary>
        /// Initializes a new cost tracker.
        /// </summary>
        /// <param name="config">Configuration for budget tracking.</param>
        public LlmCostTracker(CostTrackerConfig? config = null)
        {
            _config = config ?? new CostTrackerConfig();
            _entries = new ConcurrentBag<CostEntry>();
            _lastDailyReset = GetDayStart(DateTimeOffset.UtcNow);
            _lastMonthlyReset = GetMonthStart(DateTimeOffset.UtcNow);
        }

        /// <summary>
        /// Tracks cost for a completed request.
        /// </summary>
        /// <param name="entry">Cost entry to record.</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        public Task TrackAsync(CostEntry entry, CancellationToken cancellationToken = default)
        {
            if (_disposed) return Task.CompletedTask;

            _entries.Add(entry);

            lock (_lock)
            {
                CheckAndResetPeriods();
                _currentDailyCost += entry.CostUsd;
                _currentMonthlyCost += entry.CostUsd;
                _currentDailyTokens += entry.InputTokens + entry.OutputTokens;
                _currentMonthlyTokens += entry.InputTokens + entry.OutputTokens;
            }

            if (_config.PersistToDisk && !string.IsNullOrEmpty(_config.StoragePath))
            {
                PersistEntry(entry);
            }

            return Task.CompletedTask;
        }

        /// <summary>
        /// Estimates the cost of a request before sending it.
        /// </summary>
        /// <param name="provider">Provider name.</param>
        /// <param name="model">Model name.</param>
        /// <param name="inputTokens">Estimated input tokens.</param>
        /// <param name="outputTokens">Estimated output tokens.</param>
        /// <returns>Estimated cost in USD.</returns>
        public decimal EstimateCost(string provider, string model, int inputTokens, int outputTokens)
        {
            var pricing = GetModelPricing(model);
            decimal inputCost = (decimal)inputTokens / 1_000_000m * pricing.InputCostPer1M;
            decimal outputCost = (decimal)outputTokens / 1_000_000m * pricing.OutputCostPer1M;
            return inputCost + outputCost;
        }

        /// <summary>
        /// Checks whether a request would exceed budget limits.
        /// </summary>
        /// <param name="estimatedCost">Estimated cost in USD.</param>
        /// <returns>True if within budget.</returns>
        public bool CheckBudget(decimal estimatedCost)
        {
            if (!_config.EnforceLimits) return true;

            lock (_lock)
            {
                CheckAndResetPeriods();

                if (_config.PerRequestCeilingUsd.HasValue &&
                    estimatedCost > _config.PerRequestCeilingUsd.Value)
                    return false;

                if (_config.DailyBudgetUsd.HasValue &&
                    _currentDailyCost + estimatedCost > _config.DailyBudgetUsd.Value)
                    return false;

                if (_config.MonthlyBudgetUsd.HasValue &&
                    _currentMonthlyCost + estimatedCost > _config.MonthlyBudgetUsd.Value)
                    return false;
            }

            return true;
        }

        /// <summary>
        /// Gets daily usage report.
        /// </summary>
        /// <param name="date">Date to report on.</param>
        /// <returns>Usage report.</returns>
        public UsageReport GetDailyReport(DateTimeOffset? date = null)
        {
            var targetDate = date ?? DateTimeOffset.UtcNow;
            var dayStart = GetDayStart(targetDate);
            var dayEnd = dayStart.AddDays(1);

            var entries = _entries
                .Where(e => e.Timestamp >= dayStart && e.Timestamp < dayEnd)
                .ToList();

            return BuildReport(entries, "Daily", dayStart, dayEnd);
        }

        /// <summary>
        /// Gets monthly usage report.
        /// </summary>
        /// <param name="date">Date in the target month.</param>
        /// <returns>Usage report.</returns>
        public UsageReport GetMonthlyReport(DateTimeOffset? date = null)
        {
            var targetDate = date ?? DateTimeOffset.UtcNow;
            var monthStart = GetMonthStart(targetDate);
            var monthEnd = monthStart.AddMonths(1);

            var entries = _entries
                .Where(e => e.Timestamp >= monthStart && e.Timestamp < monthEnd)
                .ToList();

            return BuildReport(entries, "Monthly", monthStart, monthEnd);
        }

        /// <summary>
        /// Gets usage breakdown by provider.
        /// </summary>
        /// <returns>Provider usage dictionary.</returns>
        public IReadOnlyDictionary<string, ProviderUsage> GetProviderBreakdown()
        {
            var breakdown = new Dictionary<string, ProviderUsage>(StringComparer.OrdinalIgnoreCase);

            foreach (var entry in _entries)
            {
                if (!breakdown.TryGetValue(entry.Provider, out var usage))
                {
                    usage = new ProviderUsage { Provider = entry.Provider };
                    breakdown[entry.Provider] = usage;
                }

                breakdown[entry.Provider] = usage with
                {
                    TotalCostUsd = usage.TotalCostUsd + entry.CostUsd,
                    TotalInputTokens = usage.TotalInputTokens + entry.InputTokens,
                    TotalOutputTokens = usage.TotalOutputTokens + entry.OutputTokens,
                    RequestCount = usage.RequestCount + 1
                };
            }

            return breakdown;
        }

        /// <summary>
        /// Exports cost data to CSV format.
        /// </summary>
        /// <returns>CSV string.</returns>
        public string ExportCsv()
        {
            var sb = new StringBuilder();
            sb.AppendLine("Timestamp,Provider,Model,InputTokens,OutputTokens,CostUsd,TaskType");

            foreach (var entry in _entries.OrderBy(e => e.Timestamp))
            {
                sb.AppendLine($"{entry.Timestamp:O},{entry.Provider},{entry.Model}," +
                    $"{entry.InputTokens},{entry.OutputTokens},{entry.CostUsd:F6},{entry.TaskType}");
            }

            return sb.ToString();
        }

        /// <summary>
        /// Exports cost data to JSON format.
        /// </summary>
        /// <returns>JSON string.</returns>
        public string ExportJson()
        {
            return JsonSerializer.Serialize(_entries.OrderBy(e => e.Timestamp).ToList(),
                new JsonSerializerOptions { WriteIndented = true });
        }

        /// <summary>
        /// Gets cost optimization suggestions based on usage patterns.
        /// </summary>
        /// <returns>List of suggestions.</returns>
        public IReadOnlyList<string> GetOptimizationSuggestions()
        {
            var suggestions = new List<string>();
            var breakdown = GetProviderBreakdown();

            foreach (var (provider, usage) in breakdown)
            {
                if (usage.RequestCount > 100 && usage.TotalCostUsd > 1.0m)
                {
                    var avgCostPerRequest = usage.TotalCostUsd / usage.RequestCount;
                    if (avgCostPerRequest > 0.01m)
                    {
                        suggestions.Add(
                            $"Provider '{provider}' averages ${avgCostPerRequest:F4} per request. " +
                            $"Consider using a cheaper model for simple tasks.");
                    }
                }
            }

            var dailyReport = GetDailyReport();
            if (dailyReport.TotalCostUsd > (_config.DailyBudgetUsd ?? decimal.MaxValue) * 0.8m)
            {
                suggestions.Add("Daily budget is approaching 80% usage. Consider reducing request volume.");
            }

            return suggestions;
        }

        /// <inheritdoc/>
        public void Dispose()
        {
            if (_disposed) return;
            _disposed = true;
        }

        // ─── Private Helpers ───────────────────────────────────────────────

        private void CheckAndResetPeriods()
        {
            var now = DateTimeOffset.UtcNow;
            var currentDayStart = GetDayStart(now);
            if (currentDayStart > _lastDailyReset)
            {
                _currentDailyCost = 0;
                _currentDailyTokens = 0;
                _lastDailyReset = currentDayStart;
            }

            var currentMonthStart = GetMonthStart(now);
            if (currentMonthStart > _lastMonthlyReset)
            {
                _currentMonthlyCost = 0;
                _currentMonthlyTokens = 0;
                _lastMonthlyReset = currentMonthStart;
            }
        }

        private static DateTimeOffset GetDayStart(DateTimeOffset dt)
        {
            return new DateTimeOffset(dt.Year, dt.Month, dt.Day, 0, 0, 0, dt.Offset);
        }

        private static DateTimeOffset GetMonthStart(DateTimeOffset dt)
        {
            return new DateTimeOffset(dt.Year, dt.Month, 1, 0, 0, 0, dt.Offset);
        }

        private static (decimal InputCostPer1M, decimal OutputCostPer1M) GetModelPricing(string model)
        {
            return model switch
            {
                var m when m.Contains("gpt-4o-mini") => (0.15m, 0.60m),
                var m when m.Contains("gpt-4o") => (2.50m, 10.00m),
                var m when m.Contains("gpt-4-turbo") => (10.00m, 30.00m),
                var m when m.Contains("claude-sonnet") => (3.00m, 15.00m),
                var m when m.Contains("claude-haiku") => (0.80m, 4.00m),
                var m when m.Contains("gemini-flash") => (0.075m, 0.30m),
                var m when m.Contains("gemini-pro") => (1.25m, 5.00m),
                _ => (0m, 0m)
            };
        }

        private static UsageReport BuildReport(
            List<CostEntry> entries, string period,
            DateTimeOffset start, DateTimeOffset end)
        {
            var byProvider = entries.GroupBy(e => e.Provider)
                .ToDictionary(g => g.Key, g => g.Sum(e => e.CostUsd));
            var byModel = entries.GroupBy(e => e.Model)
                .ToDictionary(g => g.Key, g => g.Sum(e => e.CostUsd));

            return new UsageReport
            {
                Period = period,
                StartDate = start,
                EndDate = end,
                TotalCostUsd = entries.Sum(e => e.CostUsd),
                TotalInputTokens = entries.Sum(e => e.InputTokens),
                TotalOutputTokens = entries.Sum(e => e.OutputTokens),
                TotalRequests = entries.Count,
                CostByProvider = byProvider,
                CostByModel = byModel
            };
        }

        private void PersistEntry(CostEntry entry)
        {
            try
            {
                if (string.IsNullOrEmpty(_config.StoragePath)) return;
                if (!Directory.Exists(_config.StoragePath))
                    Directory.CreateDirectory(_config.StoragePath);

                var filePath = Path.Combine(_config.StoragePath, $"costs_{DateTimeOffset.UtcNow:yyyyMMdd}.jsonl");
                var json = JsonSerializer.Serialize(entry);
                File.AppendAllText(filePath, json + Environment.NewLine);
            }
            catch { /* Best effort persistence */ }
        }
    }

    /// <summary>
    /// Usage report for a time period.
    /// </summary>
    public record UsageReport
    {
        /// <summary>Report period type (Daily, Monthly).</summary>
        public string Period { get; init; } = string.Empty;

        /// <summary>Start of the reporting period.</summary>
        public DateTimeOffset StartDate { get; init; }

        /// <summary>End of the reporting period.</summary>
        public DateTimeOffset EndDate { get; init; }

        /// <summary>Total cost in USD.</summary>
        public decimal TotalCostUsd { get; init; }

        /// <summary>Total input tokens.</summary>
        public int TotalInputTokens { get; init; }

        /// <summary>Total output tokens.</summary>
        public int TotalOutputTokens { get; init; }

        /// <summary>Total requests.</summary>
        public int TotalRequests { get; init; }

        /// <summary>Cost breakdown by provider.</summary>
        public IReadOnlyDictionary<string, decimal> CostByProvider { get; init; } =
            new Dictionary<string, decimal>();

        /// <summary>Cost breakdown by model.</summary>
        public IReadOnlyDictionary<string, decimal> CostByModel { get; init; } =
            new Dictionary<string, decimal>();
    }

    /// <summary>
    /// Usage statistics for a single provider.
    /// </summary>
    public record ProviderUsage
    {
        /// <summary>Provider name.</summary>
        public string Provider { get; init; } = string.Empty;

        /// <summary>Total cost in USD.</summary>
        public decimal TotalCostUsd { get; init; }

        /// <summary>Total input tokens.</summary>
        public int TotalInputTokens { get; init; }

        /// <summary>Total output tokens.</summary>
        public int TotalOutputTokens { get; init; }

        /// <summary>Total request count.</summary>
        public int RequestCount { get; init; }
    }

    #endregion
    // =========================================================================
}
